final Map<RenderObject, String> _boxFitByRenderObject = {};
final Set<RenderObject> _rotatedBoxNodes = {};
String? _asyncExportResult;
bool _asyncExportBusy = false;

void _markCaptureRecursive(RenderObject ro) {
  _customPaintCaptures.add(ro);
  ro.visitChildren((child) => _markCaptureRecursive(child));
}

/// RenderShaderMask의 public shaderCallback getter를 dynamic dispatch로 접근,
/// 사각형에 shader를 직접 칠한 뒤 픽셀 샘플링으로 gradient 추출.
/// 256px 해상도, 전체 축 스캔 + 색상 변화점 기반 stop 추출,
/// 4방향(H/V/대각선) + radial 판별 지원.
Future<void> _extractShaderMaskGradients(RenderObject root) async {
  final List<RenderBox> nodes = [];
  void find(RenderObject ro) {
    final name = ro.runtimeType.toString();
    if (name.contains('ShaderMask') && ro is RenderBox && ro.hasSize) {
      nodes.add(ro);
    }
    ro.visitChildren(find);
  }

  find(root);
  debugPrint('[ShaderMask] found ${nodes.length} nodes');

  for (final node in nodes) {
    try {
      final w = node.size.width;
      final h = node.size.height;
      if (w <= 0 || h <= 0) continue;

      final dynamic dynNode = node;
      final Function callback = dynNode.shaderCallback as Function;
      final rect = Offset.zero & Size(w, h);
      final shader = callback(rect) as ui.Shader;

      // 고해상도 캔버스 (최대 256px)
      final sw = w.ceil().clamp(4, 256);
      final sh = h.ceil().clamp(4, 256);
      final recorder = ui.PictureRecorder();
      final canvas = Canvas(recorder);
      canvas.drawRect(
        Rect.fromLTWH(0, 0, sw.toDouble(), sh.toDouble()),
        Paint()..shader = shader,
      );
      final picture = recorder.endRecording();
      final image = await picture.toImage(sw, sh);
      final byteData = await image.toByteData(
        format: ui.ImageByteFormat.rawRgba,
      );
      image.dispose();
      if (byteData == null) continue;

      Color getPixel(int x, int y) {
        x = x.clamp(0, sw - 1);
        y = y.clamp(0, sh - 1);
        final off = (y * sw + x) * 4;
        return Color.fromARGB(
          byteData.getUint8(off + 3),
          byteData.getUint8(off),
          byteData.getUint8(off + 1),
          byteData.getUint8(off + 2),
        );
      }

      double colorDist(Color a, Color b) => ((a.red - b.red).abs() +
              (a.green - b.green).abs() +
              (a.blue - b.blue).abs())
          .toDouble();

      // 축별 색상 라인 샘플링 (전체 축 스캔)
      List<Color> sampleLine(
        int Function(int i) xFn,
        int Function(int i) yFn,
        int count,
      ) {
        final result = <Color>[];
        for (int i = 0; i < count; i++) {
          result.add(getPixel(xFn(i), yFn(i)));
        }
        return result;
      }

      double lineVariance(List<Color> line) {
        double v = 0;
        for (int i = 1; i < line.length; i++) {
          v += colorDist(line[i - 1], line[i]);
        }
        return v;
      }

      // 4방향 분산 측정: H, V, 대각선(\), 대각선(/)
      final hLine = sampleLine((i) => i, (i) => sh ~/ 2, sw); // horizontal mid
      final vLine = sampleLine((i) => sw ~/ 2, (i) => i, sh); // vertical mid
      final dim = sw < sh ? sw : sh;
      final d1Line = sampleLine(
        (i) => (i * (sw - 1)) ~/ (dim - 1),
        (i) => (i * (sh - 1)) ~/ (dim - 1),
        dim,
      ); // top-left → bottom-right
      final d2Line = sampleLine(
        (i) => ((dim - 1 - i) * (sw - 1)) ~/ (dim - 1),
        (i) => (i * (sh - 1)) ~/ (dim - 1),
        dim,
      ); // top-right → bottom-left

      final hVar = lineVariance(hLine);
      final vVar = lineVariance(vLine);
      final d1Var = lineVariance(d1Line);
      final d2Var = lineVariance(d2Line);

      // Gradient 타입 판별: 분산 대칭성 기반
      // - Linear: 한 방향 분산이 압도적 (수직 방향 분산은 낮음)
      // - Radial: 모든 방향 분산이 비슷 + 같은 반지름 대칭 색 일치
      // - Sweep: 각도별 색 변화 + 반지름 방향 변화 없음
      final maxLinearVar = [hVar, vVar, d1Var, d2Var].reduce(math.max);
      final minLinearVar = [hVar, vVar, d1Var, d2Var].reduce(math.min);

      bool isRadial = false;
      bool isSweep = false;

      // 분산 대칭 비율: 1.0에 가까우면 모든 방향 비슷 (radial), 0에 가까우면 한 방향만 높음 (linear)
      final symmetryRatio =
          maxLinearVar > 0 ? minLinearVar / maxLinearVar : 0.0;

      final cx = sw ~/ 2;
      final cy = sh ~/ 2;

      // Radial 검사: 대칭 비율 높고 + 같은 반지름 대칭점 색 일치
      // + 중심 색이 모서리 색과 다름 (방사형 확인)
      if (symmetryRatio > 0.4 && maxLinearVar > 30) {
        final ringLR = colorDist(
          getPixel(sw ~/ 4, cy),
          getPixel(3 * sw ~/ 4, cy),
        );
        final ringTB = colorDist(
          getPixel(cx, sh ~/ 4),
          getPixel(cx, 3 * sh ~/ 4),
        );
        final ringSymmetry = ringLR + ringTB;
        // 중심과 모서리 색 차이 (radial이면 커야 함)
        final centerColor = getPixel(cx, cy);
        final cornerDist = (colorDist(centerColor, getPixel(0, 0)) +
                colorDist(centerColor, getPixel(sw - 1, 0)) +
                colorDist(centerColor, getPixel(0, sh - 1)) +
                colorDist(centerColor, getPixel(sw - 1, sh - 1))) /
            4;
        isRadial = ringSymmetry < 40 && cornerDist > 30;
      }

      // Sweep 검사: 원형 샘플링으로 각도별 분산 vs 반지름 분산 비교
      // symmetryRatio > 0.5: 모든 방향 분산 비슷할 때만 (linear는 한 방향만 높아서 ratio 낮음)
      if (!isRadial && maxLinearVar > 30 && symmetryRatio > 0.5) {
        // 반지름 방향 분산 (중심→오른쪽)
        final radLine = sampleLine(
          (i) => cx + (i * (sw ~/ 2)) ~/ dim,
          (i) => cy,
          dim,
        );
        final radVar = lineVariance(radLine);

        // 각도별 분산: 원형 8포인트 샘플링
        final r = (sw < sh ? sw : sh) * 0.3;
        final angularColors = <Color>[];
        for (int ai = 0; ai < 8; ai++) {
          final angle = 2 * math.pi * ai / 8;
          final px = (cx + r * math.cos(angle)).round().clamp(0, sw - 1);
          final py = (cy + r * math.sin(angle)).round().clamp(0, sh - 1);
          angularColors.add(getPixel(px, py));
        }
        double angularVar = 0;
        for (int ai = 1; ai < angularColors.length; ai++) {
          angularVar += colorDist(angularColors[ai - 1], angularColors[ai]);
        }
        angularVar += colorDist(angularColors.last, angularColors.first);

        // Sweep: 각도별 분산 높고, 반지름 분산은 각도별의 30% 미만
        isSweep = angularVar > 100 && radVar < angularVar * 0.3;
      }

      String gradType;
      List<Color> bestLine;
      double beginX, beginY, endX, endY;

      final gcx = sw ~/ 2;
      final gcy = sh ~/ 2;

      if (isRadial) {
        gradType = 'radial';
        bestLine = sampleLine(
          (i) => gcx + (i * (sw ~/ 2)) ~/ dim,
          (i) => gcy,
          dim,
        );
        beginX = 0.5;
        beginY = 0.5;
        endX = 1.0;
        endY = 0.5;
      } else if (isSweep) {
        gradType = 'sweep';
        final sweepCount = 128;
        final sweepLine = <Color>[];
        // 각도별로 가용 반지름을 최대한 활용 (타원형 샘플링)
        final rx = (sw ~/ 2) * 0.85; // 가로 반지름
        final ry = (sh ~/ 2) * 0.85; // 세로 반지름
        for (int i = 0; i < sweepCount; i++) {
          final angle = 2 * math.pi * i / sweepCount;
          final px = (gcx + rx * math.cos(angle)).round();
          final py = (gcy + ry * math.sin(angle)).round();
          sweepLine.add(getPixel(px.clamp(0, sw - 1), py.clamp(0, sh - 1)));
        }
        bestLine = sweepLine;
        beginX = 0.5;
        beginY = 0.5;
        endX = 0.5;
        endY = 0.5;
      } else {
        // Linear: 최대 분산 방향 선택
        // 축 정렬(H/V)과 대각선 분산이 비슷하면(10% 이내) 축 정렬 우선
        final axisMax = math.max(hVar, vVar);
        final diagMax = math.max(d1Var, d2Var);
        int best;
        if (axisMax >= diagMax * 0.9) {
          best = hVar >= vVar ? 0 : 1;
        } else {
          best = d1Var >= d2Var ? 2 : 3;
        }
        switch (best) {
          case 0: // horizontal
            bestLine = hLine;
            beginX = 0.0;
            beginY = 0.5;
            endX = 1.0;
            endY = 0.5;
            break;
          case 1: // vertical
            bestLine = vLine;
            beginX = 0.5;
            beginY = 0.0;
            endX = 0.5;
            endY = 1.0;
            break;
          case 2: // diagonal TL→BR
            bestLine = d1Line;
            beginX = 0.0;
            beginY = 0.0;
            endX = 1.0;
            endY = 1.0;
            break;
          default: // diagonal TR→BL
            bestLine = d2Line;
            beginX = 1.0;
            beginY = 0.0;
            endX = 0.0;
            endY = 1.0;
            break;
        }
        gradType = 'linear';
      }

      // 최대 편차 기반 stop 추출 (Ramer-Douglas-Peucker 방식)
      // 선형 보간과 실제 색의 차이가 가장 큰 지점을 반복적으로 stop에 추가
      final len = bestLine.length;

      Color lerpColor(Color a, Color b, double t) {
        return Color.fromARGB(
          (a.alpha + (b.alpha - a.alpha) * t).round().clamp(0, 255),
          (a.red + (b.red - a.red) * t).round().clamp(0, 255),
          (a.green + (b.green - a.green) * t).round().clamp(0, 255),
          (a.blue + (b.blue - a.blue) * t).round().clamp(0, 255),
        );
      }

      // 초기: 첫 + 마지막
      final stopIndices = <int>[0, len - 1];

      // 반복: 최대 편차 지점 추가 (최대 8개 stop까지)
      const maxStops = 8;
      const deviationThreshold = 20.0;
      while (stopIndices.length < maxStops) {
        double maxDev = 0;
        int maxIdx = -1;

        // 인접 stop 쌍 사이에서 최대 편차 찾기
        for (int s = 0; s < stopIndices.length - 1; s++) {
          final si = stopIndices[s];
          final ei = stopIndices[s + 1];
          if (ei - si <= 1) continue;

          final startColor = bestLine[si];
          final endColor = bestLine[ei];

          for (int i = si + 1; i < ei; i++) {
            final t = (i - si) / (ei - si);
            final expected = lerpColor(startColor, endColor, t);
            final dev = colorDist(bestLine[i], expected);
            if (dev > maxDev) {
              maxDev = dev;
              maxIdx = i;
            }
          }
        }

        if (maxDev < deviationThreshold || maxIdx < 0) break;

        stopIndices.add(maxIdx);
        stopIndices.sort();
      }

      final colors = <String>[];
      final stops = <double>[];
      for (final idx in stopIndices) {
        colors.add(_colorToHex(bestLine[idx])!);
        stops.add(idx / (len - 1));
      }

      final gradient = <String, dynamic>{
        'type': gradType,
        'colors': colors,
        'stops': stops,
      };

      if (gradType == 'radial') {
        gradient['center'] = {'x': 0.5, 'y': 0.5};
        gradient['radius'] = 0.5;
      } else if (gradType == 'sweep') {
        gradient['center'] = {'x': 0.5, 'y': 0.5};
      } else {
        gradient['begin'] = {'x': beginX, 'y': beginY};
        gradient['end'] = {'x': endX, 'y': endY};
      }

      debugPrint(
        '[ShaderMask] type=$gradType colors=${colors.length} '
        'hVar=$hVar vVar=$vVar d1=$d1Var d2=$d2Var isRadial=$isRadial isSweep=$isSweep',
      );

      void mapAll(RenderObject obj) {
        _shaderMaskGradients[obj] = gradient;
        obj.visitChildren(mapAll);
      }

      node.visitChildren(mapAll);
    } catch (e, st) {
      debugPrint('[ShaderMask] ERROR: $e\n$st');
    }
  }
}

/// =======================================================
/// 0.5 Pre-capture: 이미지/아이콘 → base64 (async)
/// =======================================================

Future<void> _preCaptureImages(RenderObject node) async {
  // RenderImage → 축소 후 PNG 인코딩 (maxDim = 512 * pixelRatio)
  if (node is RenderImage) {
    try {
      final ui.Image? img = node.image;
      if (img != null) {
        final maxDim = (512 * _capturePixelRatio).round();
        int targetW = img.width;
        int targetH = img.height;
        if (targetW > maxDim || targetH > maxDim) {
          final scale = maxDim / (targetW > targetH ? targetW : targetH);
          targetW = (targetW * scale).ceil();
          targetH = (targetH * scale).ceil();
        }
        final recorder = ui.PictureRecorder();
        final canvas = Canvas(recorder);
        canvas.drawImageRect(
          img,
          Rect.fromLTWH(0, 0, img.width.toDouble(), img.height.toDouble()),
          Rect.fromLTWH(0, 0, targetW.toDouble(), targetH.toDouble()),
          Paint(),
        );
        final picture = recorder.endRecording();
        final resized = await picture.toImage(targetW, targetH);
        final byteData = await resized.toByteData(
          format: ui.ImageByteFormat.png,
        );
        if (byteData != null) {
          _imageDataByNode[node] = base64Encode(byteData.buffer.asUint8List());
        }
      }
    } catch (_) {}
  }

  // MaterialIcons → TextPainter → PictureRecorder → toImage()
  if (node is RenderParagraph) {
    try {
      final span = node.text;
      if (span is TextSpan &&
          span.style?.fontFamily?.contains('MaterialIcons') == true) {
        final double pr = _capturePixelRatio;
        final outW = (node.size.width * pr).ceil();
        final outH = (node.size.height * pr).ceil();
        final recorder = ui.PictureRecorder();
        final canvas = Canvas(
          recorder,
          Rect.fromLTWH(0, 0, outW.toDouble(), outH.toDouble()),
        );
        canvas.scale(pr);
        final painter = TextPainter(
          text: span,
          textDirection: TextDirection.ltr,
        );
        painter.layout();
        painter.paint(canvas, Offset.zero);
        final picture = recorder.endRecording();
        final img = await picture.toImage(outW, outH);
        final byteData = await img.toByteData(format: ui.ImageByteFormat.png);
        if (byteData != null) {
          _imageDataByNode[node] = base64Encode(byteData.buffer.asUint8List());
        }
      }
    } catch (_) {}
  }

  // CustomPaint with painter → 투명 배경에 painter만 직접 paint
  if (node is RenderBox &&
      _customPainterByRO.containsKey(node) &&
      !_imageDataByNode.containsKey(node)) {
    try {
      final painter = _customPainterByRO[node]!;
      final w = node.size.width;
      final h = node.size.height;
      if (w > 0 && h > 0) {
        final double pr = _capturePixelRatio;
        final outW = (w * pr).round();
        final outH = (h * pr).round();
        final recorder = ui.PictureRecorder();
        final canvas = Canvas(
          recorder,
          Rect.fromLTWH(0, 0, outW.toDouble(), outH.toDouble()),
        );
        canvas.scale(pr);
        painter.paint(canvas, Size(w, h));
        final picture = recorder.endRecording();
        final img = await picture.toImage(outW, outH);
        final byteData = await img.toByteData(format: ui.ImageByteFormat.png);
        img.dispose();
        if (byteData != null) {
          _imageDataByNode[node] = base64Encode(byteData.buffer.asUint8List());
        }
      }
    } catch (e) {
      debugPrint('[CustomPainter] direct paint failed: $e');
    }
  }

  // Checkbox / Switch / RangeSlider 등 → 투명 배경에 직접 paint (우선)
  // 사방 4px 여유 포함하여 overflow paint(리플/그림자) 캡처
  if (node is RenderBox &&
      _customPaintCaptures.contains(node) &&
      !_imageDataByNode.containsKey(node)) {
    try {
      final w = node.size.width;
      final h = node.size.height;
      if (w > 0 && h > 0) {
        final double pr = _capturePixelRatio;
        const double pad = 4.0;
        final paintW = w + pad * 2;
        final paintH = h + pad * 2;
        final layer = OffsetLayer();
        final context = PaintingContext(
          layer,
          Rect.fromLTWH(0, 0, paintW, paintH),
        );
        node.paint(context, Offset(pad, pad));
        context.stopRecordingIfNeeded();
        final img = await layer.toImage(
          Rect.fromLTWH(0, 0, paintW, paintH),
          pixelRatio: pr,
        );
        final byteData = await img.toByteData(format: ui.ImageByteFormat.png);
        if (byteData != null) {
          _imageDataByNode[node] = base64Encode(byteData.buffer.asUint8List());
        }
      }
    } catch (e) {
      debugPrint(
        '[preCapture] direct paint FAILED for ${node.runtimeType}: $e',
      );
    }
  }

  // Fallback: direct paint 실패 시 RepaintBoundary crop
  if (node is RenderBox &&
      _customPaintCaptures.contains(node) &&
      !_imageDataByNode.containsKey(node)) {
    try {
      final w = node.size.width;
      final h = node.size.height;
      if (w > 0 && h > 0) {
        final double pr = _capturePixelRatio;
        const double pad = 4.0;
        RenderObject? ancestor = node.parent;
        RenderRepaintBoundary? bestBoundary;
        while (ancestor != null) {
          if (ancestor is RenderRepaintBoundary) {
            bestBoundary = ancestor;
            if (ancestor.size.width >= w + pad * 2 &&
                ancestor.size.height >= h + pad * 2) {
              break;
            }
          }
          ancestor = ancestor.parent;
        }
        ancestor = bestBoundary;
        if (ancestor is RenderRepaintBoundary) {
          final img = await ancestor.toImage(pixelRatio: pr);
          final nodeOffset = node.localToGlobal(Offset.zero);
          final boundaryOffset = (ancestor as RenderBox).localToGlobal(
            Offset.zero,
          );
          final outW = ((w + pad * 2) * pr).round();
          final outH = ((h + pad * 2) * pr).round();
          final rawSrcX = (nodeOffset.dx - boundaryOffset.dx - pad) * pr;
          final rawSrcY = (nodeOffset.dy - boundaryOffset.dy - pad) * pr;
          final srcX = rawSrcX.clamp(0.0, img.width.toDouble());
          final srcY = rawSrcY.clamp(0.0, img.height.toDouble());
          final dstX = srcX - rawSrcX;
          final dstY = srcY - rawSrcY;
          final srcW = (outW.toDouble() - dstX).clamp(
            0.0,
            img.width.toDouble() - srcX,
          );
          final srcH = (outH.toDouble() - dstY).clamp(
            0.0,
            img.height.toDouble() - srcY,
          );
          if (srcW > 0 && srcH > 0) {
            final recorder = ui.PictureRecorder();
            final canvas = Canvas(
              recorder,
              Rect.fromLTWH(0, 0, outW.toDouble(), outH.toDouble()),
            );
            canvas.drawImageRect(
              img,
              Rect.fromLTWH(srcX, srcY, srcW, srcH),
              Rect.fromLTWH(dstX, dstY, srcW, srcH),
              Paint(),
            );
            final picture = recorder.endRecording();
            final cropped = await picture.toImage(outW, outH);
            final byteData = await cropped.toByteData(
              format: ui.ImageByteFormat.png,
            );
            if (byteData != null) {
              _imageDataByNode[node] = base64Encode(
                byteData.buffer.asUint8List(),
              );
            }
          }
        }
      }
    } catch (e) {
      debugPrint(
        '[preCapture] RepaintBoundary crop FAILED for ${node.runtimeType}: $e',
      );
    }
  }

  // 자식 재귀 (visitChildren은 sync callback → 리스트 수집 후 순회)
  final children = <RenderObject>[];
  node.visitChildren((child) => children.add(child));
  for (final child in children) {
    await _preCaptureImages(child);
  }
}

/// =======================================================
/// 1. Element 트리 순회해서 위젯 레벨 디자인 정보 수집
/// =======================================================

void _collectDesignInfoFromElements(Element element) {
  final widget = element.widget;

  if (widget is InputDecorator) {
    final InputDecoration deco = widget.decoration;
    Color? bg;
    Color? borderColor;
    double? borderWidth;
    dynamic radius;
    double? borderTopW, borderRightW, borderBottomW, borderLeftW;

    if (deco.filled == true) {
      bg = deco.fillColor;
    }

    // 포커스 상태에 따라 적절한 border 선택
    final bool isFocused = widget.isFocused;
    InputBorder? border;
    if (isFocused) {
      border = deco.focusedBorder ?? deco.border;
    } else {
      border = deco.enabledBorder ?? deco.border;
    }

    // Flutter 테마에서 resolved border color 추출 시도
    Color? themePrimaryColor;
    if (border != null &&
        border.borderSide == const BorderSide() &&
        isFocused) {
      // border가 기본 BorderSide → 테마 primary color 사용
      try {
        final themeData = Theme.of(element);
        themePrimaryColor = themeData.colorScheme.primary;
      } catch (_) {}
    }

    bool isOutlined = false;
    if (border is OutlineInputBorder) {
      isOutlined = true;
      final side = border.borderSide;
      borderColor = themePrimaryColor ?? side.color;
      borderWidth = isFocused ? math.max(side.width, 2.0) : side.width;
      final br = border.borderRadius;
      if (br is BorderRadius) {
        radius = _extractBorderRadius(br);
      }
    } else if (border is UnderlineInputBorder) {
      final side = border.borderSide;
      borderColor = themePrimaryColor ?? side.color;
      borderWidth = isFocused ? math.max(side.width, 2.0) : side.width;
      // 하단 border만 적용
      borderTopW = 0;
      borderRightW = 0;
      borderBottomW = borderWidth;
      borderLeftW = 0;
      final br = border.borderRadius;
      if (br is BorderRadius) {
        radius = _extractBorderRadius(br);
      }
    }

    // outlined + labelText → 부모 배경색 탐색 (floating label notch용)
    String? parentBgColor;
    if (isOutlined && deco.labelText != null) {
      Element? ancestor = element;
      for (int depth = 0; depth < 20 && ancestor != null; depth++) {
        Element? parent;
        ancestor.visitAncestorElements((el) {
          parent = el;
          return false;
        });
        ancestor = parent;
        if (ancestor == null) break;
        final w = ancestor.widget;
        if (w is Scaffold && w.backgroundColor != null) {
          parentBgColor = _colorToHex(w.backgroundColor);
          break;
        }
        if (w is Container && w.color != null) {
          parentBgColor = _colorToHex(w.color);
          break;
        }
        if (w is ColoredBox) {
          parentBgColor = _colorToHex(w.color);
          break;
        }
        if (w is Material && w.color != null) {
          parentBgColor = _colorToHex(w.color);
          break;
        }
      }
      parentBgColor ??= '#ffffffff';
    }

    final ro = element.renderObject;
    if (ro != null) {
      _designInfoByRenderObject[ro] = DesignInfo(
        backgroundColor: bg,
        borderColor: borderColor,
        borderWidth: borderWidth,
        borderRadius: radius,
        borderTopWidth: borderTopW,
        borderRightWidth: borderRightW,
        borderBottomWidth: borderBottomW,
        borderLeftWidth: borderLeftW,
        isTextField: true,
        isOutlinedTextField: isOutlined,
        parentBgColor: parentBgColor,
      );
    }
  }

  if (widget is Divider) {
    final ro = element.renderObject;
    if (ro != null && widget.color != null) {
      _designInfoByRenderObject[ro] = DesignInfo(
        backgroundColor: widget.color,
        isDivider: true,
      );
    }
  }

  if (widget is Container) {
    final deco = widget.decoration;
    Color? bg;
    Color? borderColor;
    double? borderWidth;
    dynamic radius;
    double? borderTopW, borderRightW, borderBottomW, borderLeftW;

    // Container(color: ...) → decoration 없이 color만 설정된 경우
    if (deco == null && widget.color != null) {
      bg = widget.color;
    }

    if (deco is BoxDecoration) {
      bg = deco.color;
      final border = deco.border;
      if (border is Border) {
        final sides = [border.top, border.right, border.bottom, border.left];
        BorderSide? best;
        for (final s in sides) {
          if (best == null || s.width > best.width) best = s;
        }
        if (best != null && best.width > 0) {
          borderColor = best.color;
          borderWidth = best.width;
        }
        final uniform = sides.every(
          (s) => s.width == sides[0].width && s.color == sides[0].color,
        );
        if (!uniform) {
          borderTopW = border.top.width;
          borderRightW = border.right.width;
          borderBottomW = border.bottom.width;
          borderLeftW = border.left.width;
        }
      }
      final br = deco.borderRadius;
      if (br is BorderRadius) {
        radius = _extractBorderRadius(br);
      }
    }

    final ro = element.renderObject;
    if (ro != null && (bg != null || borderColor != null || radius != null)) {
      _designInfoByRenderObject[ro] = DesignInfo(
        backgroundColor: bg,
        borderColor: borderColor,
        borderWidth: borderWidth,
        borderRadius: radius,
        borderTopWidth: borderTopW,
        borderRightWidth: borderRightW,
        borderBottomWidth: borderBottomW,
        borderLeftWidth: borderLeftW,
      );
    }
  }

  if (widget is ColoredBox) {
    final ro = element.renderObject;
    if (ro != null) {
      _designInfoByRenderObject[ro] = DesignInfo(backgroundColor: widget.color);
    }
  }

  if (widget.runtimeType.toString().contains('SvgPicture')) {
    final ro = element.renderObject;
    if (ro != null) {
      _svgBoxTargets.add(ro);
    }
  }

  // Material 위젯 (OutlinedButton, ElevatedButton 등의 보더)
  // _ShapeBorderPaint(CustomPaint)로 그려지는 보더는 render tree에서 추출 불가
  // → element tree에서 Material.shape.side를 직접 추출
  if (widget is Material && widget.shape != null) {
    final shape = widget.shape;
    if (shape is OutlinedBorder) {
      final side = shape.side;
      if (side.width > 0 && side.style == BorderStyle.solid) {
        dynamic radius;
        if (shape is RoundedRectangleBorder) {
          final br = shape.borderRadius;
          if (br is BorderRadius) {
            radius = _extractBorderRadius(br);
          }
        }
        final ro = element.renderObject;
        if (ro != null) {
          // 기존 DesignInfo가 있으면 덮어쓰지 않고, 없을 때만 등록
          if (!_designInfoByRenderObject.containsKey(ro)) {
            _designInfoByRenderObject[ro] = DesignInfo(
              borderColor: side.color,
              borderWidth: side.width,
              borderRadius: radius,
            );
          }
        }
      }
    }
  }

  // 전용 위젯 이름 태깅
  final widgetTypeName = widget.runtimeType.toString();
  const namedWidgets = {
    'NavigationToolbar',
    'BottomNavigationBar',
    'Scaffold',
    'AppBar',
    'ListTile',
    'CheckboxListTile',
    'RadioListTile',
    'BackButton',
    'ModalBarrier',
  };
  if (namedWidgets.contains(widgetTypeName)) {
    final ro = element.renderObject;
    if (ro != null) {
      _widgetNameByRenderObject[ro] = widgetTypeName;
    }
  }

  // Chip 계열: ComponentElement → renderObject는 하위 첫 RenderObject 반환
  if (widgetTypeName == 'Chip' || widgetTypeName == 'RawChip') {
    final ro = element.renderObject;
    if (ro != null && !_widgetNameByRenderObject.containsKey(ro)) {
      _widgetNameByRenderObject[ro] = 'Chip';
    }
  }

  // Checkbox / Switch → renderObject와 하위 자식 모두 캡처 대상 등록
  const captureWidgets = {
    'Checkbox',
    'Switch',
    'CupertinoSwitch',
    'Slider',
    'Radio',
    'RangeSlider',
    'CircularProgressIndicator',
    'LinearProgressIndicator',
    'ChoiceChip',
    'FilterChip',
    'InputChip',
    'ActionChip',
  };
  if (captureWidgets.contains(widgetTypeName)) {
    final ro = element.renderObject;
    if (ro != null) {
      _markCaptureRecursive(ro);
    }
  }

  // ShaderMask → render tree 순회로 감지 (async phase에서 처리)

  // CustomPaint with painter → painter를 직접 빈 캔버스에 paint (투명 배경)
  // child가 없는 leaf CustomPaint만 캡처 (순수 장식용)
  // Flutter 내부 CustomPaint(child 있음: ink effect, indicator 등)는 스킵 → 자연 분해
  if (widgetTypeName == 'CustomPaint') {
    final cp = widget as CustomPaint;
    if (cp.painter != null && cp.child == null) {
      final ro = element.renderObject;
      if (ro != null) {
        _customPainterByRO[ro] = cp.painter!;
        _markCaptureRecursive(ro);
      }
    }
  }

  // Card → shape, color, elevation, clipBehavior 추출
  if (widget is Card) {
    final ro = element.renderObject;
    if (ro != null) {
      Color? bg = widget.color;
      double? elevation = widget.elevation;
      dynamic radius;
      bool clips = false;

      final shape = widget.shape;
      if (shape is RoundedRectangleBorder) {
        final br = shape.borderRadius;
        if (br is BorderRadius) {
          radius = _extractBorderRadius(br);
        }
      }

      if (widget.clipBehavior != Clip.none) {
        clips = true;
      }

      if (bg != null || radius != null || elevation != null || clips) {
        _designInfoByRenderObject[ro] = DesignInfo(
          backgroundColor: bg,
          borderRadius: radius,
          elevation: elevation,
          clipsContent: clips,
        );
      }
    }
  }

  // FittedBox → boxFit 추출
  if (widget is FittedBox) {
    final ro = element.renderObject;
    if (ro != null) {
      _boxFitByRenderObject[ro] = widget.fit.toString().split('.').last;
    }
  }

  // ClipPath → clipper 등록 (async phase에서 Path 샘플링)
  if (widget is ClipPath) {
    final ro = element.renderObject;
    if (ro != null && widget.clipper != null) {
      _clipperByRenderObject[ro] = widget.clipper!;
    }
  }

  // BackdropFilter → blur sigma 추출
  if (widget is BackdropFilter) {
    try {
      final filter = widget.filter;
      final filterStr = filter.toString();
      // ImageFilter.blur(sigmaX: 10.0, sigmaY: 10.0, ...)
      final sigmaMatch = RegExp(r'sigmaX:\s*([\d.]+)').firstMatch(filterStr);
      if (sigmaMatch != null) {
        final sigma = double.tryParse(sigmaMatch.group(1)!) ?? 0;
        if (sigma > 0) {
          final ro = element.renderObject;
          if (ro != null) {
            _blurInfoByRenderObject[ro] = sigma;
          }
        }
      }
    } catch (_) {}
  }

  // Transform.rotate → angle 추출
  if (widget is Transform) {
    try {
      final ro = element.renderObject;
      if (ro != null) {
        // Transform widget의 transform Matrix4에서 rotation 추출
        final t = widget.transform;
        final sinVal = t.entry(1, 0);
        final cosVal = t.entry(0, 0);
        final radians = math.atan2(sinVal, cosVal);
        if (radians.abs() > 0.001) {
          final degrees = radians * 180.0 / math.pi;
          _rotationByRenderObject[ro] = degrees;
          debugPrint(
            '[Transform] captured rotation=${degrees.toStringAsFixed(2)}° for $ro',
          );
        }
      }
    } catch (e) {
      debugPrint('[Transform] angle extraction failed: $e');
    }
  }

  // RotatedBox → quarterTurns 추출 + 노드 등록
  if (widgetTypeName == 'RotatedBox') {
    try {
      final ro = element.renderObject;
      if (ro != null) {
        _rotatedBoxNodes.add(ro);
        final qt = (widget as dynamic).quarterTurns as int;
        final degrees = (qt % 4) * 90.0;
        if (degrees.abs() > 0.001) {
          _rotationByRenderObject[ro] = degrees;
          debugPrint(
            '[RotatedBox] captured rotation=${degrees.toStringAsFixed(0)}° for $ro',
          );
        }
      }
    } catch (e) {
      debugPrint('[RotatedBox] quarterTurns extraction failed: $e');
    }
  }

  element.visitChildren(_collectDesignInfoFromElements);
}

/// =======================================================
/// 2. 헬퍼: visual 속성 추출
/// =======================================================

/// borderRadius 문자열에서 숫자 추출
double? _parseBorderRadius(dynamic br) {
  if (br == null) return null;
  final s = br.toString();
  if (s.contains('zero')) return 0.0;
  final m = RegExp(r'\d+\.?\d*').firstMatch(s);
  if (m != null) return double.tryParse(m.group(0)!);
  return double.tryParse(s);
}

/// BorderRadius에서 per-corner 값 추출
/// uniform이면 단일 double, non-uniform이면 {tl, tr, bl, br} Map 반환
dynamic _extractBorderRadius(BorderRadius br) {
  final tl = br.topLeft.x;
  final tr = br.topRight.x;
  final bl = br.bottomLeft.x;
  final bRight = br.bottomRight.x;
  if (tl == tr && tr == bl && bl == bRight) {
    return tl; // uniform
  }
  return {'tl': tl, 'tr': tr, 'bl': bl, 'br': bRight};
}

/// gradient 추출 (LinearGradient, RadialGradient, SweepGradient)
Map<String, dynamic>? _extractGradient(dynamic gradient) {
  if (gradient == null) return null;
  final colors = <String>[];
  final stops = <double>[];
  try {
    final colorList = gradient.colors as List<Color>;
    for (final c in colorList) {
      colors.add(_colorToHex(c)!);
    }
    final stopList = gradient.stops as List<double>?;
    if (stopList != null) {
      stops.addAll(stopList);
    } else {
      for (int i = 0; i < colors.length; i++) {
        stops.add(i / (colors.length - 1));
      }
    }
  } catch (_) {
    return null;
  }

  final map = <String, dynamic>{'colors': colors, 'stops': stops};

  final typeName = gradient.runtimeType.toString();
  if (typeName.contains('LinearGradient')) {
    map['type'] = 'linear';
    try {
      final begin = gradient.begin as Alignment;
      final end = gradient.end as Alignment;
      map['begin'] = {'x': (begin.x + 1) / 2, 'y': (begin.y + 1) / 2};
      map['end'] = {'x': (end.x + 1) / 2, 'y': (end.y + 1) / 2};
    } catch (_) {
      map['begin'] = {'x': 0.5, 'y': 0.0};
      map['end'] = {'x': 0.5, 'y': 1.0};
    }
  } else if (typeName.contains('RadialGradient')) {
    map['type'] = 'radial';
    try {
      final center = gradient.center as Alignment;
      map['center'] = {'x': (center.x + 1) / 2, 'y': (center.y + 1) / 2};
      map['radius'] = gradient.radius as double;
    } catch (_) {
      map['center'] = {'x': 0.5, 'y': 0.5};
      map['radius'] = 0.5;
    }
  } else if (typeName.contains('SweepGradient')) {
    map['type'] = 'sweep';
    try {
      final center = gradient.center as Alignment;
      map['center'] = {'x': (center.x + 1) / 2, 'y': (center.y + 1) / 2};
      map['startAngle'] = gradient.startAngle as double;
      map['endAngle'] = gradient.endAngle as double;
    } catch (_) {
      map['center'] = {'x': 0.5, 'y': 0.5};
    }
  }
  return map;
}

/// 노드 트리에 실질적 콘텐츠(Text, Image, visual 있는 Frame)가 있는지
bool _hasContentRecursive(Map<String, dynamic> node) {
  final type = node['type'];
  if (type == 'Text' || type == 'Image') return true;
  final vis = node['visual'] as Map<String, dynamic>? ?? {};
  if (vis['content'] != null ||
      vis['backgroundColor'] != null ||
      vis['gradient'] != null ||
      vis['border'] != null ||
      vis['imagePath'] != null) return true;
  final children = node['children'] as List?;
  if (children == null) return false;
  for (final c in children) {
    if (c is Map<String, dynamic> && _hasContentRecursive(c)) return true;
  }
  return false;
}

/// visual 속성이 있는지 (배경, 테두리, 그림자 등)
bool _hasVisualProps(Map<String, dynamic> visual) {
  return visual['backgroundColor'] != null ||
      (visual['border'] != null) ||
      (visual['shadow'] != null) ||
      visual['borderRadius'] != null ||
      visual['isIconBox'] == true ||
      visual['isSvgBox'] == true ||
      visual['isTextField'] == true ||
      visual['isDivider'] == true ||
      visual['backgroundBlur'] != null;
}

/// =======================================================
/// 3. Render 트리 크롤러 (Schema v2)
/// =======================================================

/// SliverPadding에서 패딩을 추출하여 containerLayout에 저장
void _extractSliverPadding(RenderObject sliver, Map<String, dynamic> cl) {
  if (sliver is RenderSliverPadding) {
    final EdgeInsets? resolved = sliver.resolvedPadding;
    if (resolved != null && !cl.containsKey('padding')) {
      cl['padding'] = {
        'top': resolved.top,
        'right': resolved.right,
        'bottom': resolved.bottom,
        'left': resolved.left,
      };
    }
  }
  sliver.visitChildren((child) {
    if (child is! RenderBox) {
      _extractSliverPadding(child, cl);
    }
  });
}

List<Map<String, dynamic>> _crawlThroughSliver(RenderObject sliver) {
  // SliverGrid → ROW 단위로 그룹핑하여 COLUMN > ROW * n 구조 생성
  if (sliver is RenderSliverGrid) {
    final List<Map<String, dynamic>> gridChildren = [];
    sliver.visitChildren((child) {
      if (child is RenderBox) {
        final res = _crawl(child);
        if (res != null) gridChildren.add(res);
      }
    });
    if (gridChildren.isEmpty) return [];

    // crossAxisCount + spacing 추출 (gridDelegate에서)
    int crossAxisCount = 2; // 기본값
    double crossAxisSpacing = 0.0;
    double mainAxisSpacing = 0.0;
    try {
      final delegate = (sliver as dynamic).gridDelegate;
      if (delegate is SliverGridDelegateWithFixedCrossAxisCount) {
        crossAxisCount = delegate.crossAxisCount;
        crossAxisSpacing = delegate.crossAxisSpacing;
        mainAxisSpacing = delegate.mainAxisSpacing;
      }
    } catch (_) {}

    // 자식을 ROW 단위로 그룹핑
    final List<Map<String, dynamic>> rows = [];
    for (int i = 0; i < gridChildren.length; i += crossAxisCount) {
      final end = (i + crossAxisCount).clamp(0, gridChildren.length);
      final rowChildren = gridChildren.sublist(i, end);
      // 각 자식에 flexGrow 설정
      for (final rc in rowChildren) {
        final cl = rc['childLayout'] as Map<String, dynamic>? ?? {};
        cl['flexGrow'] = 1;
        cl['sizingH'] = 'FILL';
        cl['sizingV'] = 'HUG';
        rc['childLayout'] = cl;
      }
      // ROW 래퍼 생성
      final firstRect = rowChildren.first['rect'] as Map<String, dynamic>;
      rows.add({
        'type': 'Frame',
        'layoutMode': 'ROW',
        'rect': {
          'x': firstRect['x'],
          'y': firstRect['y'],
          'w': sliver.constraints.crossAxisExtent,
          'h': (firstRect['h'] as num).toDouble(),
        },
        'visual': <String, dynamic>{},
        'containerLayout': {
          'mainAxisAlignment': 'start',
          'crossAxisAlignment': 'start',
          'mainAxisSize': 'max',
          'itemSpacing': crossAxisSpacing,
        },
        'children': rowChildren,
      });
    }
    // 행 간격은 부모 COLUMN의 itemSpacing으로 처리됨 (mainAxisSpacing)
    // rows에 mainAxisSpacing 정보를 첨부하여 상위에서 사용
    if (rows.isNotEmpty && mainAxisSpacing > 0) {
      // _crawlThroughSliver 결과는 바로 COLUMN children이 되므로
      // 상위 _crawl에서 itemSpacing 계산 시 gap이 반영됨
    }
    return rows;
  }

  final List<Map<String, dynamic>> results = [];
  sliver.visitChildren((child) {
    if (child is RenderBox) {
      final res = _crawl(child);
      if (res != null) results.add(res);
    } else {
      results.addAll(_crawlThroughSliver(child));
    }
  });
  return results;
}

/// FittedBox 스케일 보정: Text fontSize + 자식 rect w/h 재귀 스케일
void _applyFittedBoxScale(Map<String, dynamic> node, double scale) {
  // Text → fontSize/letterSpacing 스케일
  if (node['type'] == 'Text') {
    final visual = node['visual'] as Map<String, dynamic>? ?? {};
    final origSize = visual['fontSize'];
    if (origSize is num) {
      visual['fontSize'] = (origSize * scale * 10).floorToDouble() / 10.0;
    }
    final origSpacing = visual['letterSpacing'];
    if (origSpacing is num && origSpacing != 0) {
      visual['letterSpacing'] = (origSpacing * scale * 100).round() / 100.0;
    }
    node['visual'] = visual;
  }

  // 자식 노드의 rect w/h 스케일 (아이콘 등 비텍스트 자식 포함)
  final children = node['children'] as List?;
  if (children != null) {
    for (final child in children) {
      if (child is Map<String, dynamic>) {
        final rect = child['rect'] as Map<String, dynamic>?;
        if (rect != null) {
          if (rect['w'] is num) rect['w'] = (rect['w'] as num) * scale;
          if (rect['h'] is num) rect['h'] = (rect['h'] as num) * scale;
        }
        _applyFittedBoxScale(child, scale);
      }
    }
  }
}

/// 메인 크롤 함수: RenderObject → 새 스키마 노드
Map<String, dynamic>? _crawl(RenderObject? node) {
  if (node == null) return null;

  // Sliver 노드: 통과하여 내부 RenderBox 수집
  if (node is! RenderBox) {
    final sliverChildren = _crawlThroughSliver(node);
    if (sliverChildren.isEmpty) return null;
    if (sliverChildren.length == 1) return sliverChildren.first;
    return {
      'type': 'Frame',
      'layoutMode': 'COLUMN',
      'rect': sliverChildren.first['rect'],
      'visual': <String, dynamic>{},
      'containerLayout': <String, dynamic>{},
      'children': sliverChildren,
    };
  }

  if (!node.hasSize) return null;
  if (node.size.width == 0 && node.size.height == 0) return null;
  if (node is RenderOffstage && node.offstage) return null;

  // Checkbox / Switch 등: 이미지로 캡처된 경우
  // PNG는 사방 8px 여유 포함, wrapper Frame은 실제 크기 + center/center 정렬
  if (_customPaintCaptures.contains(node)) {
    final b64 = _imageDataByNode[node];
    if (b64 != null) {
      Offset cpOffset;
      try {
        cpOffset = node.localToGlobal(Offset.zero);
      } catch (_) {
        try {
          cpOffset = (node.parentData as BoxParentData).offset;
        } catch (_) {
          cpOffset = Offset.zero;
        }
      }
      const double pad = 4.0;
      return {
        'type': 'Frame',
        'layoutMode': 'NONE',
        'clipsContent': false,
        'rect': {
          'x': cpOffset.dx,
          'y': cpOffset.dy,
          'w': node.size.width,
          'h': node.size.height,
        },
        'visual': <String, dynamic>{},
        'containerLayout': {
          'mainAxisAlignment': 'center',
          'crossAxisAlignment': 'center',
        },
        'children': <Map<String, dynamic>>[
          {
            'type': 'Image',
            'layoutMode': 'NONE',
            'rect': {
              'x': -pad,
              'y': -pad,
              'w': node.size.width + pad * 2,
              'h': node.size.height + pad * 2,
            },
            'visual': {'imageBase64': b64, 'imageFit': 'fill'},
            'children': <Map<String, dynamic>>[],
          },
        ],
      };
    }
  }

  Offset offset;
  try {
    offset = node.localToGlobal(Offset.zero);
  } catch (_) {
    return null;
  }

  // 기본값
  String type = 'Frame';
  String layoutMode = 'NONE';
  final Map<String, dynamic> visual = {};
  final Map<String, dynamic> containerLayout = {};
  bool hasVisual = false;
  bool isLayoutNode = false;
  bool isSizedBox = false;
  bool isCustomMultiChild = false;

  // RotatedBox: element tree에서 미리 등록한 노드를 직접 감지 (runtimeType 의존 제거)
  if (_rotatedBoxNodes.contains(node)) {
    final rotation = _rotationByRenderObject[node];
    RenderBox? singleChild;
    int childCount = 0;
    node.visitChildren((child) {
      childCount++;
      if (child is RenderBox) singleChild = child;
    });
    if (childCount == 1 && singleChild != null) {
      final childResult = _crawl(singleChild);
      if (childResult != null) {
        // rotation 0° → 단순 pass-through
        if (rotation == null || rotation.abs() <= 0.001) {
          childResult['rect'] = {
            'x': offset.dx,
            'y': offset.dy,
            'w': node.size.width,
            'h': node.size.height,
          };
          return childResult;
        }
        // rotation 있음 → wrapper Frame 생성
        // Figma에서 rotation은 순수 시각 변환이므로,
        // 자식은 원래(회전 전) 크기를 유지하고 wrapper가 layout 크기를 담당
        final childVisual =
            childResult['visual'] as Map<String, dynamic>? ?? {};
        childVisual['rotation'] = rotation;
        childResult['visual'] = childVisual;
        // 자식은 원래 크기 유지 (singleChild.size), wrapper 내부에 센터링
        childResult['rect'] = {
          'x': 0.0,
          'y': 0.0,
          'w': singleChild!.size.width,
          'h': singleChild!.size.height,
        };
        final cl = childResult['childLayout'] as Map<String, dynamic>? ?? {};
        cl['fixedWidth'] = true;
        cl['fixedHeight'] = true;
        cl['fixedSize'] = true;
        childResult['childLayout'] = cl;
        return {
          'type': 'Frame',
          'layoutMode': 'NONE',
          'clipsContent': false,
          'rect': {
            'x': offset.dx,
            'y': offset.dy,
            'w': node.size.width,
            'h': node.size.height,
          },
          'visual': <String, dynamic>{},
          'containerLayout': {
            'mainAxisAlignment': 'center',
            'crossAxisAlignment': 'center',
          },
          'children': <Map<String, dynamic>>[childResult],
        };
      }
    }
    // 자식 없으면 빈 Frame으로 fall through
  }

  final String runtimeTypeStr = node.runtimeType.toString();
  final bool isSvgBoxTarget = _svgBoxTargets.contains(node);

  String? backgroundImagePath;
  String? backgroundImageFit;

  // ---------------------------------------------------
  // [0] SvgPicture placeholder
  // ---------------------------------------------------
  if (isSvgBoxTarget) {
    hasVisual = true;
    visual['backgroundColor'] = '#ffdddddd';
    visual['isSvgBox'] = true;
  }
  // ---------------------------------------------------
  // [1] Text / Icon
  // ---------------------------------------------------
  else if (node is RenderParagraph) {
    TextStyle? style;
    InlineSpan inlineSpan = node.text;
    if (inlineSpan is TextSpan) {
      style = inlineSpan.style;
    }
    final String? fontFamily = style?.fontFamily;

    if (fontFamily != null && fontFamily.contains('MaterialIcons')) {
      type = 'Frame';
      hasVisual = true;
      final Color color = style?.color ?? const Color(0xFF000000);
      visual['backgroundColor'] = _colorToHex(color);
      visual['isIconBox'] = true;
      // pre-captured 아이콘 이미지 lookup
      final b64 = _imageDataByNode[node];
      if (b64 != null) {
        visual['iconImageBase64'] = b64;
      }
    } else {
      type = 'Text';
      hasVisual = true;
      try {
        visual['content'] = node.text.toPlainText();
        visual['textAlign'] = node.textAlign.toString().split('.').last;

        // RichText children: 개별 TextSpan 스타일을 textSpans 배열로 내보내기
        if (inlineSpan is TextSpan) {
          final spanChildren = inlineSpan.children;
          if (spanChildren != null && spanChildren.isNotEmpty) {
            final spans = <Map<String, dynamic>>[];
            int charOffset = 0;
            for (final child in spanChildren) {
              if (child is TextSpan) {
                final spanText = child.text ?? '';
                if (spanText.isNotEmpty) {
                  final spanMap = <String, dynamic>{
                    'start': charOffset,
                    'end': charOffset + spanText.length,
                  };
                  final s = child.style;
                  if (s != null) {
                    if (s.fontSize != null) spanMap['fontSize'] = s.fontSize;
                    if (s.fontWeight != null)
                      spanMap['fontWeight'] = s.fontWeight.toString();
                    if (s.color != null)
                      spanMap['color'] = _colorToHex(s.color);
                    if (s.fontFamily != null)
                      spanMap['fontFamily'] = s.fontFamily;
                    if (s.letterSpacing != null)
                      spanMap['letterSpacing'] = s.letterSpacing;
                    if (s.height != null)
                      spanMap['lineHeightMultiplier'] = s.height;
                  }
                  spans.add(spanMap);
                  charOffset += spanText.length;
                }
              }
            }
            if (spans.isNotEmpty) {
              visual['textSpans'] = spans;
            }
            // 최상위 style이 없으면 첫 번째 자식 style을 fallback
            if (style == null ||
                (style.fontSize == null && style.fontWeight == null)) {
              final first = spanChildren.first;
              if (first is TextSpan && first.style != null) {
                style = first.style;
              }
            }
          }
        }

        if (style != null) {
          visual['fontFamily'] = style.fontFamily;
          visual['fontSize'] = style.fontSize;
          visual['fontWeight'] = style.fontWeight.toString();
          visual['color'] = _colorToHex(style.color);
          visual['letterSpacing'] = style.letterSpacing;
          if (style.height != null) {
            visual['lineHeightMultiplier'] = style.height;
          }
        }
      } catch (_) {}

      // maxLines / textOverflow 수집
      if (node.maxLines != null) {
        visual['maxLines'] = node.maxLines;
      }
      final overflowName = node.overflow.toString().split('.').last;
      if (overflowName != 'clip') {
        // clip이 기본값이므로 clip이 아닌 경우만 출력
        visual['textOverflow'] = overflowName;
      }
      if (node.softWrap == false) {
        visual['softWrap'] = false;
      }

      // ShaderMask gradient → 텍스트에 gradient fill 적용
      final smGradient = _shaderMaskGradients[node];
      if (smGradient != null) {
        visual['gradient'] = smGradient;
      }
    }
  }
  // ---------------------------------------------------
  // [1.5] Editable Text (TextField 입력 텍스트)
  // ---------------------------------------------------
  else if (node is RenderEditable) {
    type = 'Text';
    hasVisual = true;
    visual['isEditable'] = true;
    try {
      final text = node.text;
      final plainText = text?.toPlainText() ?? '';
      if (plainText.isNotEmpty) {
        visual['content'] = plainText;
        visual['textAlign'] = node.textAlign.toString().split('.').last;
        TextStyle? style;
        if (text is TextSpan) {
          style = text.style;
        }
        if (style != null) {
          visual['fontFamily'] = style.fontFamily;
          visual['fontSize'] = style.fontSize;
          visual['fontWeight'] = style.fontWeight.toString();
          visual['color'] = _colorToHex(style.color);
          visual['letterSpacing'] = style.letterSpacing;
          if (style.height != null) {
            visual['lineHeightMultiplier'] = style.height;
          }
        }
      }
    } catch (_) {}
  }
  // ---------------------------------------------------
  // [2] Image
  // ---------------------------------------------------
  else if (node is RenderImage) {
    type = 'Image';
    hasVisual = true;
    try {
      visual['imagePath'] = node.debugImageLabel;
      visual['imageFit'] = 'cover';
      // pre-captured 이미지 데이터 lookup
      final b64 = _imageDataByNode[node];
      if (b64 != null) {
        visual['imageBase64'] = b64;
      }
    } catch (_) {}
  }
  // ---------------------------------------------------
  // [2.5] Padding (RenderPadding) — 자식에 병합
  // ---------------------------------------------------
  else if (node is RenderPadding) {
    final EdgeInsetsGeometry resolvedPadding = node.padding;
    EdgeInsets insets;
    if (resolvedPadding is EdgeInsets) {
      insets = resolvedPadding;
    } else {
      insets = resolvedPadding.resolve(TextDirection.ltr);
    }

    final paddingMap = {
      'top': insets.top,
      'right': insets.right,
      'bottom': insets.bottom,
      'left': insets.left,
    };

    RenderBox? singleChild;
    int childCount = 0;
    node.visitChildren((child) {
      childCount++;
      if (child is RenderBox) singleChild = child;
    });

    // Padding + RenderFlex → padding을 Flex containerLayout에 병합
    if (childCount == 1 && singleChild is RenderFlex) {
      final flexResult = _crawl(singleChild);
      if (flexResult != null) {
        final cl = flexResult['containerLayout'] as Map<String, dynamic>? ?? {};
        cl['padding'] = paddingMap;
        flexResult['containerLayout'] = cl;
        flexResult['rect'] = {
          'x': offset.dx,
          'y': offset.dy,
          'w': node.size.width,
          'h': node.size.height,
        };
        return flexResult;
      }
    }

    // Padding + RenderStack → padding을 Stack containerLayout에 병합
    if (childCount == 1 && singleChild is RenderStack) {
      final stackResult = _crawl(singleChild);
      if (stackResult != null) {
        final cl =
            stackResult['containerLayout'] as Map<String, dynamic>? ?? {};
        cl['padding'] = paddingMap;
        stackResult['containerLayout'] = cl;
        stackResult['rect'] = {
          'x': offset.dx,
          'y': offset.dy,
          'w': node.size.width,
          'h': node.size.height,
        };
        return stackResult;
      }
    }

    // Flex 자식인 Padding → cross축 padding 여부로 wrapper/투과 결정
    if (childCount == 1 && singleChild != null && node.parent is RenderFlex) {
      final parentFlex = node.parent! as RenderFlex;
      final isParentHorizontal = parentFlex.direction == Axis.horizontal;
      // cross축 padding이 있으면 content padding → wrapper 필요
      final hasCrossAxisPadding = isParentHorizontal
          ? (insets.top > 0 || insets.bottom > 0)
          : (insets.left > 0 || insets.right > 0);

      final childResult = _crawl(singleChild);
      if (childResult != null) {
        if (hasCrossAxisPadding) {
          // cross축 padding → wrapper Frame 생성 (content padding 보존)
          return <String, dynamic>{
            'type': 'Frame',
            'layoutMode': isParentHorizontal ? 'ROW' : 'COLUMN',
            'rect': {
              'x': offset.dx,
              'y': offset.dy,
              'w': node.size.width,
              'h': node.size.height,
            },
            'visual': <String, dynamic>{},
            'containerLayout': <String, dynamic>{
              'padding': paddingMap,
              'mainAxisAlignment': 'start',
              'crossAxisAlignment': 'stretch',
              'mainAxisSize': 'min',
              'itemSpacing': 0.0,
            },
            'children': [childResult],
          };
        } else {
          // main축만 padding → 투과 (margin/spacing 패턴)
          return childResult;
        }
      }
    }

    // Padding + RenderDecoratedBox → margin 패턴 (Container(margin:...))
    // 투명 wrapper Frame(auto-layout + padding)으로 margin 표현
    // → 자식 요소 크기는 유지, wrapper의 padding이 margin 역할
    if (childCount == 1 && singleChild is RenderDecoratedBox) {
      final childResult = _crawl(singleChild);
      if (childResult != null) {
        return <String, dynamic>{
          'type': 'Frame',
          'layoutMode': 'COLUMN',
          'rect': {
            'x': offset.dx,
            'y': offset.dy,
            'w': node.size.width,
            'h': node.size.height,
          },
          'visual': <String, dynamic>{},
          'containerLayout': <String, dynamic>{
            'padding': paddingMap,
            'mainAxisAlignment': 'start',
            'crossAxisAlignment': 'stretch',
            'mainAxisSize': 'min',
            'itemSpacing': 0.0,
          },
          'children': [childResult],
        };
      }
    }

    // 기타: Frame(COLUMN) + padding
    // RenderPadding은 tight constraints를 자식에게 전달 → stretch가 올바른 매핑
    type = 'Frame';
    layoutMode = 'COLUMN';
    isLayoutNode = true;
    containerLayout['padding'] = paddingMap;
    containerLayout['mainAxisAlignment'] = 'start';
    containerLayout['crossAxisAlignment'] = 'stretch';
    containerLayout['mainAxisSize'] = 'min';
    containerLayout['itemSpacing'] = 0.0;
  }
  // ---------------------------------------------------
  // [3] RenderStack (신규)
  // ---------------------------------------------------
  else if (node is RenderStack) {
    type = 'Frame';
    layoutMode = 'STACK';
    isLayoutNode = true;
    // Stack의 clipBehavior 추출 (기본값: Clip.hardEdge)
    try {
      final clip = node.clipBehavior;
      if (clip != Clip.none) {
        visual['clipsContent'] = true;
      }
    } catch (_) {}
  }
  // ---------------------------------------------------
  // [3.5] RenderPositionedBox (Align / Center / Container.alignment)
  // ---------------------------------------------------
  else if (node is RenderPositionedBox) {
    type = 'Frame';
    isLayoutNode = true;
    layoutMode = 'COLUMN';

    final alignment = node.alignment;
    Alignment resolved;
    if (alignment is Alignment) {
      resolved = alignment;
    } else {
      resolved = alignment.resolve(TextDirection.ltr);
    }

    // alignment.y → mainAxisAlignment (COLUMN = vertical)
    String mainAlign;
    if (resolved.y <= -0.5) {
      mainAlign = 'start';
    } else if (resolved.y >= 0.5) {
      mainAlign = 'end';
    } else {
      mainAlign = 'center';
    }

    // alignment.x → crossAxisAlignment (COLUMN = horizontal)
    String crossAlign;
    if (resolved.x <= -0.5) {
      crossAlign = 'start';
    } else if (resolved.x >= 0.5) {
      crossAlign = 'end';
    } else {
      crossAlign = 'center';
    }

    containerLayout['mainAxisAlignment'] = mainAlign;
    containerLayout['crossAxisAlignment'] = crossAlign;
    containerLayout['mainAxisSize'] = 'max';
  }
  // ---------------------------------------------------
  // [4] RenderConstrainedBox (SizedBox)
  // ---------------------------------------------------
  else if (node is RenderConstrainedBox) {
    isSizedBox = true;
    // 자식 확인
    RenderBox? singleChild;
    int childCount = 0;
    node.visitChildren((child) {
      childCount++;
      if (child is RenderBox) singleChild = child;
    });

    if (childCount == 1 && singleChild != null) {
      // 자식 있으면 투과 — 크기 정보만 childLayout에서 처리
      final childResult = _crawl(singleChild);
      if (childResult != null) {
        // rect를 SizedBox 기준으로 업데이트
        childResult['rect'] = {
          'x': offset.dx,
          'y': offset.dy,
          'w': node.size.width,
          'h': node.size.height,
        };
        // Tight constraints → fixedSize / fixedWidth / fixedHeight 마킹
        // 렌더 크기 ≈ 제약 크기일 때만 (Expanded 안 SizedBox 제외)
        final ac = node.additionalConstraints;
        final cl = childResult['childLayout'] as Map<String, dynamic>? ?? {};
        bool marked = false;
        if (ac.hasTightWidth && ac.maxWidth.isFinite) {
          if ((node.size.width - ac.maxWidth).abs() < 1.0) {
            cl['fixedWidth'] = true;
            marked = true;
          }
        }
        if (ac.hasTightWidth && !ac.maxWidth.isFinite) {
          cl['sizingH'] = 'FILL';
          marked = true;
        }
        if (ac.hasTightHeight && ac.maxHeight.isFinite) {
          if ((node.size.height - ac.maxHeight).abs() < 1.0) {
            cl['fixedHeight'] = true;
            marked = true;
          }
        }
        if (ac.hasTightHeight && !ac.maxHeight.isFinite) {
          cl['sizingV'] = 'FILL';
          marked = true;
        }
        if (cl['fixedWidth'] == true && cl['fixedHeight'] == true) {
          cl['fixedSize'] = true;
        }
        if (marked) {
          childResult['childLayout'] = cl;
        }
        return childResult;
      }
    }

    // 자식 없으면 Spacer 역할 (빈 Frame)
    type = 'Frame';
    layoutMode = 'NONE';
  }
  // ---------------------------------------------------
  // [4.5] RenderAspectRatio (AspectRatio)
  // ---------------------------------------------------
  else if (runtimeTypeStr.contains('RenderAspectRatio')) {
    RenderBox? singleChild;
    int childCount = 0;
    node.visitChildren((child) {
      childCount++;
      if (child is RenderBox) singleChild = child;
    });
    if (childCount == 1 && singleChild != null) {
      final childResult = _crawl(singleChild);
      if (childResult != null) {
        childResult['rect'] = {
          'x': offset.dx,
          'y': offset.dy,
          'w': node.size.width,
          'h': node.size.height,
        };
        final cl = childResult['childLayout'] as Map<String, dynamic>? ?? {};
        cl['fixedWidth'] = true;
        cl['fixedHeight'] = true;
        cl['fixedSize'] = true;
        childResult['childLayout'] = cl;
        return childResult;
      }
    }
    // 자식 없으면 빈 Frame
    type = 'Frame';
    layoutMode = 'NONE';
  }
  // ---------------------------------------------------
  // [5] Flex (Row / Column)
  // ---------------------------------------------------
  else if (node is RenderFlex) {
    type = 'Frame';
    isLayoutNode = true;
    layoutMode = node.direction == Axis.horizontal ? 'ROW' : 'COLUMN';

    final mainAlign = node.mainAxisAlignment.toString().split('.').last;
    final crossAlign = node.crossAxisAlignment.toString().split('.').last;
    final mainSize = node.mainAxisSize == MainAxisSize.min ? 'min' : 'max';

    containerLayout['mainAxisAlignment'] = mainAlign;
    containerLayout['crossAxisAlignment'] = crossAlign;
    containerLayout['mainAxisSize'] = mainSize;
  }
  // ---------------------------------------------------
  // [5.5] RenderWrap
  // ---------------------------------------------------
  else if (node is RenderWrap) {
    type = 'Frame';
    isLayoutNode = true;
    layoutMode = 'WRAP';
    containerLayout['itemSpacing'] = node.spacing;
    containerLayout['runSpacing'] = node.runSpacing;
    containerLayout['mainAxisAlignment'] =
        node.alignment.toString().split('.').last;
    containerLayout['crossAxisAlignment'] =
        node.crossAxisAlignment.toString().split('.').last;
    // Wrap은 constraints.maxWidth로 줄바꿈 → Figma에서도 이 너비가 필요
    // node.size.width는 자식 바운딩 박스만 반영하므로 constraints.maxWidth 사용
    final maxW = node.constraints.maxWidth;
    if (maxW.isFinite && maxW > node.size.width) {
      containerLayout['_wrapMaxWidth'] = maxW;
    }
  }
  // ---------------------------------------------------
  // [6] DecoratedBox
  // ---------------------------------------------------
  else if (node is RenderDecoratedBox) {
    type = 'Frame';
    try {
      final decoration = node.decoration;
      if (decoration is BoxDecoration) {
        if (decoration.color != null) {
          visual['backgroundColor'] = _colorToHex(decoration.color);
          hasVisual = true;
        }
        if (decoration.gradient != null) {
          final grad = _extractGradient(decoration.gradient);
          if (grad != null) {
            visual['gradient'] = grad;
            hasVisual = true;
          }
        }
        if (decoration.image != null) {
          final DecorationImage decorationImage = decoration.image!;
          final ImageProvider provider = decorationImage.image;
          if (provider is AssetImage) {
            backgroundImagePath = provider.assetName;
            backgroundImageFit = decorationImage.fit?.toString();
            hasVisual = true;
          }
        }
        if (decoration.border != null) {
          final border = decoration.border;
          if (border is Border) {
            final top = border.top,
                right = border.right,
                bottom = border.bottom,
                left = border.left;
            final sides = [top, right, bottom, left];
            BorderSide? bestSide;
            for (final s in sides) {
              if (bestSide == null || s.width > bestSide.width) bestSide = s;
            }
            if (bestSide != null && bestSide.width > 0) {
              final borderMap = <String, dynamic>{
                'color': _colorToHex(bestSide.color),
                'width': bestSide.width,
              };
              final uniform = sides.every(
                (s) => s.width == top.width && s.color == top.color,
              );
              if (!uniform) {
                borderMap['topWidth'] = top.width;
                borderMap['rightWidth'] = right.width;
                borderMap['bottomWidth'] = bottom.width;
                borderMap['leftWidth'] = left.width;
              }
              visual['border'] = borderMap;
              hasVisual = true;
            }
          } else {
            visual['border'] = {'color': '#ff000000', 'width': 1.0};
            hasVisual = true;
          }
        }
        // BoxShape.circle → borderRadius = shortestSide / 2
        if (decoration.shape == BoxShape.circle) {
          visual['borderRadius'] = node.size.shortestSide / 2;
        } else if (decoration.borderRadius is BorderRadius) {
          final brVal = _extractBorderRadius(
            decoration.borderRadius as BorderRadius,
          );
          if (brVal != null) visual['borderRadius'] = brVal;
        } else {
          final br = _parseBorderRadius(decoration.borderRadius);
          if (br != null) visual['borderRadius'] = br;
        }
        if (decoration.boxShadow != null && decoration.boxShadow!.isNotEmpty) {
          final s = decoration.boxShadow!.first;
          visual['shadow'] = {
            'color': _colorToHex(s.color),
            'offsetX': s.offset.dx,
            'offsetY': s.offset.dy,
            'blurRadius': s.blurRadius,
            'spreadRadius': s.spreadRadius,
          };
          hasVisual = true;
        }
      }
      // ShapeDecoration (Material 버튼: OutlinedButton, ElevatedButton 등)
      else if (decoration is ShapeDecoration) {
        if (decoration.color != null) {
          visual['backgroundColor'] = _colorToHex(decoration.color);
          hasVisual = true;
        }
        final shape = decoration.shape;
        if (shape is RoundedRectangleBorder) {
          final side = shape.side;
          if (side.width > 0 && side.style == BorderStyle.solid) {
            visual['border'] = {
              'color': _colorToHex(side.color),
              'width': side.width,
            };
            hasVisual = true;
          }
          if (shape.borderRadius is BorderRadius) {
            final brVal = _extractBorderRadius(
              shape.borderRadius as BorderRadius,
            );
            if (brVal != null) visual['borderRadius'] = brVal;
          } else {
            final br = _parseBorderRadius(shape.borderRadius);
            if (br != null) visual['borderRadius'] = br;
          }
        } else if (shape is StadiumBorder) {
          final side = shape.side;
          if (side.width > 0 && side.style == BorderStyle.solid) {
            visual['border'] = {
              'color': _colorToHex(side.color),
              'width': side.width,
            };
            hasVisual = true;
          }
          // StadiumBorder → borderRadius = height / 2
          visual['borderRadius'] = node.size.height / 2;
        } else if (shape is CircleBorder) {
          final side = shape.side;
          if (side.width > 0 && side.style == BorderStyle.solid) {
            visual['border'] = {
              'color': _colorToHex(side.color),
              'width': side.width,
            };
            hasVisual = true;
          }
          visual['borderRadius'] = node.size.shortestSide / 2;
        }
        if (decoration.shadows != null && decoration.shadows!.isNotEmpty) {
          final s = decoration.shadows!.first;
          visual['shadow'] = {
            'color': _colorToHex(s.color),
            'offsetX': s.offset.dx,
            'offsetY': s.offset.dy,
            'blurRadius': s.blurRadius,
            'spreadRadius': s.spreadRadius,
          };
          hasVisual = true;
        }
      }
    } catch (_) {}
  }
  // ---------------------------------------------------
  // [7] PhysicalModel
  // ---------------------------------------------------
  else if (node is RenderPhysicalModel) {
    type = 'Frame';
    hasVisual = true;
    visual['backgroundColor'] = _colorToHex(node.color);
    if (node.elevation > 0) {
      visual['shadow'] = {'elevation': node.elevation};
    }
    if (node.clipBehavior != Clip.none) {
      visual['clipsContent'] = true;
    }
    try {
      dynamic d = node;
      if (d.borderRadius != null) {
        final br = _parseBorderRadius(d.borderRadius);
        if (br != null) visual['borderRadius'] = br;
      }
    } catch (_) {}
  }
  // ---------------------------------------------------
  // [8] PhysicalShape
  // ---------------------------------------------------
  else if (node is RenderPhysicalShape) {
    type = 'Frame';
    hasVisual = true;
    visual['backgroundColor'] = _colorToHex(node.color);
    if (node.elevation > 0) {
      visual['shadow'] = {'elevation': node.elevation};
    }
    try {
      final diagnostics = node.toDiagnosticsNode();
      final properties = diagnostics.getProperties();
      final clipperProp = properties.firstWhere(
        (p) => p.name == 'clipper',
        orElse: () => DiagnosticsProperty('dummy', null),
      );
      if (clipperProp.value != null) {
        dynamic clipper = clipperProp.value;
        dynamic shape = clipper.shape;
        final shapeStr = shape.toString();
        final reg = RegExp(r'circular\(([\d\.]+)\)');
        final m = reg.firstMatch(shapeStr);
        if (m != null) {
          visual['borderRadius'] = double.tryParse(m.group(1)!) ?? 0.0;
        }
        // shape.side → border (OutlinedButton 등 Material 버튼의 보더)
        try {
          final side = shape.side;
          if (side != null &&
              side.width > 0 &&
              side.style == BorderStyle.solid) {
            visual['border'] = {
              'color': _colorToHex(side.color),
              'width': side.width,
            };
          }
        } catch (_) {}
      }
    } catch (_) {}
  }
  // ---------------------------------------------------
  // [8.3] RenderOpacity / RenderAnimatedOpacity
  // ---------------------------------------------------
  else if (node is RenderOpacity) {
    final double opacityValue = node.opacity;
    if (opacityValue < 0.01) return null; // 투명 → 스킵
    RenderBox? singleChild;
    int childCount = 0;
    node.visitChildren((child) {
      childCount++;
      if (child is RenderBox) singleChild = child;
    });
    if (childCount == 1 && singleChild != null) {
      final childResult = _crawl(singleChild);
      if (childResult != null) {
        final childVisual =
            childResult['visual'] as Map<String, dynamic>? ?? {};
        childVisual['opacity'] = opacityValue;
        childResult['visual'] = childVisual;
        childResult['rect'] = {
          'x': offset.dx,
          'y': offset.dy,
          'w': node.size.width,
          'h': node.size.height,
        };
        return childResult;
      }
    }
    type = 'Frame';
    layoutMode = 'NONE';
    visual['opacity'] = opacityValue;
  } else if (node.runtimeType.toString().contains('AnimatedOpacity')) {
    // RenderAnimatedOpacity (hint text 등 애니메이션 opacity)
    try {
      final double opacityValue = (node as dynamic).opacity.value as double;
      if (opacityValue < 0.01) return null; // 투명 → 스킵
      RenderBox? singleChild;
      int childCount = 0;
      node.visitChildren((child) {
        childCount++;
        if (child is RenderBox) singleChild = child;
      });
      if (childCount == 1 && singleChild != null) {
        final childResult = _crawl(singleChild);
        if (childResult != null) {
          final childVisual =
              childResult['visual'] as Map<String, dynamic>? ?? {};
          childVisual['opacity'] = opacityValue;
          childResult['visual'] = childVisual;
          childResult['rect'] = {
            'x': offset.dx,
            'y': offset.dy,
            'w': node.size.width,
            'h': node.size.height,
          };
          return childResult;
        }
      }
      type = 'Frame';
      layoutMode = 'NONE';
      visual['opacity'] = opacityValue;
    } catch (_) {
      // fallback: 일반 노드로 처리
    }
  }
  // ---------------------------------------------------
  // [8.4] _RenderVisibility (Visibility + maintainSize: true)
  // maintainSize: false 인 경우 Offstage로 처리되어 이 분기에 오지 않음
  // ---------------------------------------------------
  else if (runtimeTypeStr == '_RenderVisibility') {
    bool visible = true;
    try {
      visible = (node as dynamic).visible as bool;
    } catch (_) {}

    // visible 여부와 관계없이 자식 통과
    RenderBox? singleChild;
    int childCount = 0;
    node.visitChildren((child) {
      childCount++;
      if (child is RenderBox) singleChild = child;
    });
    if (childCount == 1 && singleChild != null) {
      final childResult = _crawl(singleChild);
      if (childResult != null) {
        if (!visible) {
          // visible: false + maintainSize: true → opacity 0
          final childVisual =
              childResult['visual'] as Map<String, dynamic>? ?? {};
          childVisual['opacity'] = 0.0;
          childResult['visual'] = childVisual;
        }
        childResult['rect'] = {
          'x': offset.dx,
          'y': offset.dy,
          'w': node.size.width,
          'h': node.size.height,
        };
        return childResult;
      }
    }
    type = 'Frame';
    layoutMode = 'NONE';
    if (!visible) visual['opacity'] = 0.0;
  }
  // ---------------------------------------------------
  // [8.5] RenderClipRRect
  // ---------------------------------------------------
  else if (node is RenderClipRRect) {
    // per-corner radius 추출
    dynamic brValue;
    try {
      final brr = node.borderRadius;
      if (brr is BorderRadius) {
        brValue = _extractBorderRadius(brr);
      }
    } catch (_) {}
    brValue ??= _parseBorderRadius(node.borderRadius);

    RenderBox? singleChild;
    int childCount = 0;
    node.visitChildren((child) {
      childCount++;
      if (child is RenderBox) singleChild = child;
    });
    if (childCount == 1 && singleChild != null) {
      final childResult = _crawl(singleChild);
      if (childResult != null) {
        if (brValue != null) {
          final childVisual =
              childResult['visual'] as Map<String, dynamic>? ?? {};
          if (!childVisual.containsKey('borderRadius')) {
            childVisual['borderRadius'] = brValue;
            childResult['visual'] = childVisual;
          }
        }
        childResult['rect'] = {
          'x': offset.dx,
          'y': offset.dy,
          'w': node.size.width,
          'h': node.size.height,
        };
        return childResult;
      }
    }
    type = 'Frame';
    layoutMode = 'NONE';
    if (brValue != null) visual['borderRadius'] = brValue;
  }
  // ---------------------------------------------------
  // [8.52] RenderClipOval
  // ---------------------------------------------------
  else if (node is RenderClipOval) {
    // 원형 클리핑: borderRadius = min(width, height) / 2
    final double ovalRadius = math.min(node.size.width, node.size.height) / 2;

    RenderBox? singleChild;
    int childCount = 0;
    node.visitChildren((child) {
      childCount++;
      if (child is RenderBox) singleChild = child;
    });
    if (childCount == 1 && singleChild != null) {
      final childResult = _crawl(singleChild);
      if (childResult != null) {
        final childVisual =
            childResult['visual'] as Map<String, dynamic>? ?? {};
        if (!childVisual.containsKey('borderRadius')) {
          childVisual['borderRadius'] = ovalRadius;
          childResult['visual'] = childVisual;
        }
        childVisual['clipsContent'] = true;
        childResult['visual'] = childVisual;
        childResult['rect'] = {
          'x': offset.dx,
          'y': offset.dy,
          'w': node.size.width,
          'h': node.size.height,
        };
        return childResult;
      }
    }
    type = 'Frame';
    layoutMode = 'NONE';
    visual['borderRadius'] = ovalRadius;
    visual['clipsContent'] = true;
  }
  // ---------------------------------------------------
  // [8.55] RenderBackdropFilter → backgroundBlur
  // ---------------------------------------------------
  else if (runtimeTypeStr.contains('RenderBackdropFilter')) {
    type = 'Frame';
    layoutMode = 'NONE';
    // blur sigma를 visual에 추가 (element tree 매핑 우선, 실패 시 직접 추출)
    double? blurSigma = _blurInfoByRenderObject[node];
    if (blurSigma == null || blurSigma <= 0) {
      // fallback: RenderBackdropFilter.filter에서 직접 추출
      try {
        final filterObj = (node as dynamic).filter;
        final filterStr = filterObj.toString();
        // "sigmaX: 10.0" 형식
        var m = RegExp(r'sigmaX:\s*([\d.]+)').firstMatch(filterStr);
        // "blur(10.0, 10.0, ...)" 형식 (parameter name 없는 경우)
        m ??= RegExp(r'blur\(([\d.]+)').firstMatch(filterStr);
        if (m != null) {
          blurSigma = double.tryParse(m.group(1)!) ?? 0;
        }
      } catch (e) {
        debugPrint('[BackdropFilter] filter extraction failed: $e');
      }
    }
    if (blurSigma != null && blurSigma > 0) {
      visual['backgroundBlur'] = blurSigma;
      hasVisual = true;
    }
  }
  // ---------------------------------------------------
  // [8.57] RenderTransform → rotation 추출
  // ---------------------------------------------------
  else if (runtimeTypeStr.contains('RenderTransform')) {
    type = 'Frame';
    layoutMode = 'NONE';
    // 방법 1 (확실): widget tree에서 미리 캡처한 rotation 사용
    final precomputed = _rotationByRenderObject[node];
    if (precomputed != null && precomputed.abs() > 0.001) {
      visual['rotation'] = precomputed;
    } else {
      // 방법 2 (fallback): RenderObject에서 직접 추출 시도
      try {
        Matrix4? transform;
        try {
          transform = (node as dynamic).transform as Matrix4?;
        } catch (_) {}
        transform ??= (() {
          try {
            final parent = node.parent;
            if (parent is RenderObject) return node.getTransformTo(parent);
          } catch (_) {}
          return null;
        })();
        if (transform != null) {
          final sinVal = transform.entry(1, 0);
          final cosVal = transform.entry(0, 0);
          final radians = math.atan2(sinVal, cosVal);
          if (radians.abs() > 0.001) {
            visual['rotation'] = radians * 180.0 / math.pi;
          }
        }
      } catch (e) {
        debugPrint('[RenderTransform] rotation extraction failed: $e');
      }
    }
    // 단일 자식이면 패스스루
    RenderBox? singleChild;
    int childCount = 0;
    node.visitChildren((child) {
      childCount++;
      if (child is RenderBox) singleChild = child;
    });
    if (childCount == 1 && singleChild != null) {
      final childResult = _crawl(singleChild);
      if (childResult != null) {
        // rotation을 자식에 전파
        if (visual.containsKey('rotation')) {
          final childVisual =
              childResult['visual'] as Map<String, dynamic>? ?? {};
          childVisual['rotation'] = visual['rotation'];
          childResult['visual'] = childVisual;
        }
        childResult['rect'] = {
          'x': offset.dx,
          'y': offset.dy,
          'w': node.size.width,
          'h': node.size.height,
        };
        return childResult;
      }
    }
  }
  // ---------------------------------------------------
  // [8.6] RenderClipPath
  // ---------------------------------------------------
  else if (runtimeTypeStr.contains('RenderClipPath')) {
    final clipPoints = _clipPathPoints[node];

    RenderBox? singleChild;
    int childCount = 0;
    node.visitChildren((child) {
      childCount++;
      if (child is RenderBox) singleChild = child;
    });
    if (childCount == 1 && singleChild != null) {
      final childResult = _crawl(singleChild);
      if (childResult != null) {
        childResult['rect'] = {
          'x': offset.dx,
          'y': offset.dy,
          'w': node.size.width,
          'h': node.size.height,
        };
        if (clipPoints != null && clipPoints.isNotEmpty) {
          childResult['clipPath'] = clipPoints;
        }
        return childResult;
      }
    }
    type = 'Frame';
    layoutMode = 'NONE';
    if (clipPoints != null && clipPoints.isNotEmpty) {
      visual['clipPath'] = clipPoints;
    }
  }
  // [8.65] RenderRotatedBox — element tree 기반 early-return으로 이동 (위쪽 _rotatedBoxNodes 블록)
  // ---------------------------------------------------
  // [8.7] RenderFittedBox
  // ---------------------------------------------------
  else if (node is RenderFittedBox) {
    final String? boxFit = _boxFitByRenderObject[node];
    RenderBox? singleChild;
    int childCount = 0;
    node.visitChildren((child) {
      childCount++;
      if (child is RenderBox) singleChild = child;
    });
    if (childCount == 1 && singleChild != null) {
      final sc = singleChild!;
      final childResult = _crawl(sc);
      if (childResult != null) {
        final double parentW = node.size.width;
        final double parentH = node.size.height;
        final double childW = sc.size.width;
        final double childH = sc.size.height;

        double scaleX = childW > 0 ? parentW / childW : 1.0;
        double scaleY = childH > 0 ? parentH / childH : 1.0;
        final String fitKey = (boxFit ?? 'contain').toLowerCase();
        double scale;
        if (fitKey == 'cover') {
          scale = math.max(scaleX, scaleY);
        } else if (fitKey == 'fitwidth') {
          scale = scaleX;
        } else if (fitKey == 'fitheight') {
          scale = scaleY;
        } else if (fitKey == 'none') {
          scale = 1.0;
        } else {
          // contain, scaleDown, fill → 모두 min(scaleX, scaleY) 사용
          // fill은 비균일 스케일이지만 fontSize는 균일만 가능하므로 contain으로 근사
          scale = math.min(scaleX, scaleY);
          if (fitKey == 'scaledown' && scale > 1.0) scale = 1.0;
        }

        // 자식 트리 전체 스케일 보정 (Text fontSize + 자식 rect w/h)
        if (scale != 1.0) {
          _applyFittedBoxScale(childResult, scale);
        }
        // FittedBox 자식은 정확한 크기가 보장되므로 fixedSize 마킹
        final cl = childResult['childLayout'] as Map<String, dynamic>? ?? {};
        cl['fixedSize'] = true;
        cl['fixedWidth'] = true;
        cl['fixedHeight'] = true;
        childResult['childLayout'] = cl;

        // FittedBox alignment (기본 center)
        if (childResult['type'] == 'Frame') {
          // Frame 자식 → containerLayout으로 중앙 정렬
          final containerLayout =
              childResult['containerLayout'] as Map<String, dynamic>? ?? {};
          containerLayout['mainAxisAlignment'] = 'center';
          containerLayout['crossAxisAlignment'] = 'center';
          childResult['containerLayout'] = containerLayout;
        } else if (childResult['type'] == 'Text') {
          // Text 자식 → visual에 중앙 정렬 플래그
          final childVisual =
              childResult['visual'] as Map<String, dynamic>? ?? {};
          childVisual['textAlignVertical'] = 'center';
          childResult['visual'] = childVisual;
        }

        childResult['rect'] = {
          'x': offset.dx,
          'y': offset.dy,
          'w': parentW,
          'h': parentH,
        };
        return childResult;
      }
    }
    type = 'Frame';
    layoutMode = 'NONE';
  }
  // ---------------------------------------------------
  // [9] Picture / CustomPaint
  // ---------------------------------------------------
  else if (runtimeTypeStr.contains('Picture') ||
      runtimeTypeStr.contains('CustomPaint')) {
    type = 'Frame';
    hasVisual = false;
  }
  // ---------------------------------------------------
  // [9.5] CustomMultiChildLayout (NavigationToolbar, Scaffold 등)
  // ---------------------------------------------------
  else if (runtimeTypeStr.contains('CustomMultiChildLayoutBox')) {
    type = 'Frame';
    isLayoutNode = true;
    isCustomMultiChild = true;

    // 자식 좌표를 보고 방향 추론
    double minX = double.infinity, maxX = -double.infinity;
    double minY = double.infinity, maxY = -double.infinity;
    int peekCount = 0;
    node.visitChildren((child) {
      if (child is RenderBox && child.hasSize) {
        try {
          final o = child.localToGlobal(Offset.zero);
          if (o.dx < minX) minX = o.dx;
          if (o.dx > maxX) maxX = o.dx;
          if (o.dy < minY) minY = o.dy;
          if (o.dy > maxY) maxY = o.dy;
          peekCount++;
        } catch (_) {}
      }
    });

    if (peekCount >= 2) {
      final xRange = maxX - minX;
      final yRange = maxY - minY;
      layoutMode = xRange > yRange ? 'ROW' : 'COLUMN';
    } else {
      layoutMode = 'ROW';
    }

    if (layoutMode == 'ROW') {
      containerLayout['mainAxisAlignment'] = 'spaceBetween';
      containerLayout['crossAxisAlignment'] = 'center';
      containerLayout['mainAxisSize'] = 'max';
    } else {
      containerLayout['mainAxisAlignment'] = 'start';
      containerLayout['crossAxisAlignment'] = 'stretch';
      containerLayout['mainAxisSize'] = 'max';
    }
  }

  // ---------------------------------------------------
  // [10] DesignInfo overlay (TextField, Divider, Container)
  // ---------------------------------------------------
  final designInfo = _designInfoByRenderObject[node];
  if (designInfo != null) {
    if (designInfo.backgroundColor != null) {
      visual['backgroundColor'] = _colorToHex(designInfo.backgroundColor);
      hasVisual = true;
    }
    if (designInfo.borderColor != null) {
      final borderMap = <String, dynamic>{
        'color': _colorToHex(designInfo.borderColor),
        'width': designInfo.borderWidth ?? 1.0,
      };
      if (designInfo.borderTopWidth != null) {
        borderMap['topWidth'] = designInfo.borderTopWidth;
        borderMap['rightWidth'] = designInfo.borderRightWidth;
        borderMap['bottomWidth'] = designInfo.borderBottomWidth;
        borderMap['leftWidth'] = designInfo.borderLeftWidth;
      }
      visual['border'] = borderMap;
      hasVisual = true;
    }
    if (designInfo.borderRadius != null) {
      visual['borderRadius'] = designInfo.borderRadius;
    }
    if (designInfo.elevation != null && designInfo.elevation! > 0) {
      visual['shadow'] = {'elevation': designInfo.elevation};
    }
    if (designInfo.clipsContent) visual['clipsContent'] = true;
    if (designInfo.isTextField) visual['isTextField'] = true;
    if (designInfo.isDivider) visual['isDivider'] = true;
  }

  // ---------------------------------------------------
  // [10.5] TextField 구조 재편 플래그
  // ---------------------------------------------------
  final bool isTextFieldNode = visual['isTextField'] == true;

  // ---------------------------------------------------
  // [11] 자식 순회
  // ---------------------------------------------------
  final List<Map<String, dynamic>> children = [];
  final bool _skipChildren = (type == 'Text');
  final bool isFlex = node is RenderFlex;
  final bool isStack = node is RenderStack;
  final bool isWrap = node is RenderWrap;
  final List<double> _gaps = [];
  final List<double> _childMainAxisPositions = [];
  double? _lastChildEnd; // gap 계산용: 이전 non-null 자식의 끝 좌표

  try {
    if (!_skipChildren)
      node.visitChildren((child) {
        if (child is RenderBox) {
          final c = _crawl(child);
          if (c != null) {
            // Flex 자식: childLayout 설정
            if (isFlex) {
              final flexNode = node as RenderFlex;
              final isHorizontal = flexNode.direction == Axis.horizontal;
              final childLayout =
                  c['childLayout'] as Map<String, dynamic>? ?? {};

              final parentData = child.parentData;
              if (parentData is FlexParentData) {
                final flex = parentData.flex ?? 0;
                final isTight = parentData.fit == FlexFit.tight;

                // cross축에서 intermediate widget의 FILL을 보존할지 결정
                // stretch면 보존, 아니면 덮어씀 (center/start Column에서 FILL 방지)
                final isStretch =
                    flexNode.crossAxisAlignment == CrossAxisAlignment.stretch;

                if (flex > 0 && isTight) {
                  // Expanded
                  childLayout['flexGrow'] = flex;
                  if (isHorizontal) {
                    childLayout['sizingH'] = 'FILL';
                    childLayout['sizingV'] =
                        (isStretch && childLayout['sizingV'] == 'FILL')
                            ? 'FILL'
                            : 'HUG';
                  } else {
                    childLayout['sizingH'] =
                        (isStretch && childLayout['sizingH'] == 'FILL')
                            ? 'FILL'
                            : 'HUG';
                    childLayout['sizingV'] = 'FILL';
                  }
                } else if (flex > 0) {
                  // Flexible (loose)
                  childLayout['flexGrow'] = flex;
                  childLayout['sizingH'] = 'HUG';
                  childLayout['sizingV'] = 'HUG';
                } else {
                  // 일반 자식
                  childLayout['flexGrow'] = 0;
                  // cross축: stretch면 intermediate FILL 보존, 아니면 HUG
                  if (isHorizontal) {
                    childLayout['sizingH'] = 'HUG';
                    childLayout['sizingV'] =
                        (isStretch && childLayout['sizingV'] == 'FILL')
                            ? 'FILL'
                            : 'HUG';
                  } else {
                    childLayout['sizingH'] =
                        (isStretch && childLayout['sizingH'] == 'FILL')
                            ? 'FILL'
                            : 'HUG';
                    childLayout['sizingV'] = 'HUG';
                  }
                }
              } else {
                childLayout['flexGrow'] = 0;
                childLayout['sizingH'] = 'HUG';
                childLayout['sizingV'] = 'HUG';
              }

              // crossAxisAlignment == stretch → cross축 FILL
              if (flexNode.crossAxisAlignment == CrossAxisAlignment.stretch) {
                if (isHorizontal) {
                  childLayout['sizingV'] = 'FILL';
                  childLayout['alignSelf'] = 'STRETCH';
                } else {
                  childLayout['sizingH'] = 'FILL';
                  childLayout['alignSelf'] = 'STRETCH';
                }
              }

              c['childLayout'] = childLayout;

              // itemSpacing 계산용 좌표 수집 + gap 즉시 계산
              try {
                final childOffset = child.localToGlobal(Offset.zero);
                final pos = isHorizontal ? childOffset.dx : childOffset.dy;
                final size =
                    isHorizontal ? child.size.width : child.size.height;
                _childMainAxisPositions.add(pos);
                if (_lastChildEnd != null) {
                  final gap = pos - _lastChildEnd!;
                  if (gap > 0) _gaps.add(gap.roundToDouble());
                }
                _lastChildEnd = pos + size;
              } catch (_) {}
            }

            // Stack 자식: positioned 정보 추출
            if (isStack) {
              final childLayout =
                  c['childLayout'] as Map<String, dynamic>? ?? {};
              final parentData = child.parentData;
              if (parentData is StackParentData) {
                final pos = <String, dynamic>{};
                if (parentData.top != null) pos['top'] = parentData.top;
                if (parentData.left != null) pos['left'] = parentData.left;
                if (parentData.right != null) pos['right'] = parentData.right;
                if (parentData.bottom != null)
                  pos['bottom'] = parentData.bottom;
                if (pos.isNotEmpty) {
                  childLayout['positioned'] = pos;
                }
              }
              childLayout['sizingH'] = 'FIXED';
              childLayout['sizingV'] = 'FIXED';
              c['childLayout'] = childLayout;
            }

            // Wrap 자식: HUG 사이징 (자연 크기 유지)
            if (isWrap) {
              final childLayout =
                  c['childLayout'] as Map<String, dynamic>? ?? {};
              childLayout['sizingH'] = 'HUG';
              childLayout['sizingV'] = 'HUG';
              c['childLayout'] = childLayout;
            }

            children.add(c);
          }
        } else {
          // SliverPadding 감지 → padding + layout 설정
          _extractSliverPadding(child, containerLayout);
          if (containerLayout.containsKey('padding') && layoutMode == 'NONE') {
            layoutMode = 'COLUMN';
            isLayoutNode = true;
            containerLayout['crossAxisAlignment'] = 'stretch';
            containerLayout['mainAxisAlignment'] = 'start';
          }
          children.addAll(_crawlThroughSliver(child));
        }
      });
  } catch (_) {}

  // CustomMultiChildLayout: 자식을 위치 기준으로 정렬
  if (isCustomMultiChild && children.length >= 2) {
    if (layoutMode == 'COLUMN') {
      children.sort((a, b) {
        final ay = (a['rect'] as Map<String, dynamic>?)?['y'] as double? ?? 0.0;
        final by = (b['rect'] as Map<String, dynamic>?)?['y'] as double? ?? 0.0;
        return ay.compareTo(by);
      });
    } else {
      children.sort((a, b) {
        final ax = (a['rect'] as Map<String, dynamic>?)?['x'] as double? ?? 0.0;
        final bx = (b['rect'] as Map<String, dynamic>?)?['x'] as double? ?? 0.0;
        return ax.compareTo(bx);
      });
    }
  }

  // ---------------------------------------------------
  // [10.5] TextField 구조 재편: bg를 입력 영역에만, 패딩 적용
  // ---------------------------------------------------
  if (isTextFieldNode && children.isNotEmpty) {
    // hint/editable 중복 제거 (label은 보존):
    // RenderEditable → visual.isEditable == true
    // RenderParagraph → label 또는 hint (isEditable 없음)
    final textKids = children.where((c) => c['type'] == 'Text').toList();
    Map<String, dynamic>? editableNode;
    final List<Map<String, dynamic>> paragraphNodes = [];
    for (final tk in textKids) {
      final v = tk['visual'] as Map<String, dynamic>? ?? {};
      if (v['isEditable'] == true) {
        editableNode = tk;
      } else {
        paragraphNodes.add(tk);
      }
    }

    if (editableNode != null) {
      final editContent =
          ((editableNode['visual'] as Map?)?['content'] as String?) ?? '';
      if (editContent.isNotEmpty) {
        // 실텍스트 있음 → hint 제거 (label 제외: hint는 editable과 비슷한 y좌표)
        final editY =
            ((editableNode['rect'] as Map?)?['y'] as num?)?.toDouble() ?? 0;
        for (final p in paragraphNodes) {
          final pY = ((p['rect'] as Map?)?['y'] as num?)?.toDouble() ?? 0;
          final pContent = ((p['visual'] as Map?)?['content'] as String?) ?? '';
          // hint: editable과 y좌표가 비슷하고 (±8px), 내용이 있는 텍스트
          if ((pY - editY).abs() < 8 && pContent.isNotEmpty) {
            children.remove(p);
          }
        }
      } else {
        // 실텍스트 비어있음 → editable 노드 제거
        children.remove(editableNode);
      }
    }

    // decoration box 찾기: 콘텐츠 없는 Frame, 부모와 비슷한 너비
    int decoIdx = -1;
    for (int i = children.length - 1; i >= 0; i--) {
      final c = children[i];
      if (c['type'] == 'Frame' && !_hasContentRecursive(c)) {
        final cr = c['rect'] as Map<String, dynamic>?;
        if (cr != null) {
          final cw = (cr['w'] as num?)?.toDouble() ?? 0;
          if (cw >= node.size.width * 0.9) {
            decoIdx = i;
            break;
          }
        }
      }
    }

    if (decoIdx >= 0) {
      final decoBox = children[decoIdx];
      final decoRect = decoBox['rect'] as Map<String, dynamic>;
      final decoY = (decoRect['y'] as num).toDouble();
      final decoH = (decoRect['h'] as num).toDouble();
      final decoW = (decoRect['w'] as num).toDouble();
      final decoBottom = decoY + decoH;

      // 자식을 입력 영역 안 vs 아래(에러/헬퍼)로 분리
      final List<Map<String, dynamic>> inputChildren = [];
      final List<Map<String, dynamic>> belowChildren = [];
      Map<String, dynamic>? floatingLabel; // border 경계에 걸치는 label
      final decoX = (decoRect['x'] as num).toDouble();
      for (int i = 0; i < children.length; i++) {
        if (i == decoIdx) continue;
        final c = children[i];
        final cy = ((c['rect'] as Map?)?['y'] as num?)?.toDouble() ?? 0;
        final ch = ((c['rect'] as Map?)?['h'] as num?)?.toDouble() ?? 0;
        if (cy >= decoBottom - 1) {
          belowChildren.add(c);
        } else if (c['type'] == 'Text' &&
            (c['visual'] as Map?)?['isEditable'] != true &&
            cy < decoY &&
            (cy + ch) > decoY) {
          // label이 deco box 상단 경계를 걸쳐 있음 (floating label)
          floatingLabel = c;
        } else {
          inputChildren.add(c);
        }
      }

      // contentPadding: 전체 자식 bounding box 기반
      double bbMinX = double.infinity, bbMinY = double.infinity;
      double bbMaxX = 0, bbMaxY = 0;
      for (final ic in inputChildren) {
        final icRect = ic['rect'] as Map<String, dynamic>?;
        if (icRect != null) {
          final icX = (icRect['x'] as num?)?.toDouble() ?? 0;
          final icY = (icRect['y'] as num?)?.toDouble() ?? 0;
          final icW = (icRect['w'] as num?)?.toDouble() ?? 0;
          final icH = (icRect['h'] as num?)?.toDouble() ?? 0;
          if (icX < bbMinX) bbMinX = icX;
          if (icY < bbMinY) bbMinY = icY;
          if (icX + icW > bbMaxX) bbMaxX = icX + icW;
          if (icY + icH > bbMaxY) bbMaxY = icY + icH;
        }
      }
      Map<String, dynamic>? paddingMap;
      if (bbMinX != double.infinity) {
        final padLeft = bbMinX - decoX;
        final padTop = bbMinY - decoY;
        final padRight = decoW - (bbMaxX - decoX);
        final padBottom = decoH - (bbMaxY - decoY);
        paddingMap = {
          'top': padTop > 0 ? padTop : 0.0,
          'right': padRight > 0 ? padRight : 0.0,
          'bottom': padBottom > 0 ? padBottom : 0.0,
          'left': padLeft > 0 ? padLeft : 0.0,
        };
      }

      // 자식 좌표 기반 ROW/COLUMN 방향 추론
      String tfLayoutMode = 'COLUMN';
      if (inputChildren.length >= 2) {
        final first = inputChildren.first['rect'] as Map<String, dynamic>?;
        final last = inputChildren.last['rect'] as Map<String, dynamic>?;
        if (first != null && last != null) {
          final xRange = ((last['x'] as num?)?.toDouble() ?? 0) -
              ((first['x'] as num?)?.toDouble() ?? 0);
          final yRange = ((last['y'] as num?)?.toDouble() ?? 0) -
              ((first['y'] as num?)?.toDouble() ?? 0);
          if (xRange.abs() > yRange.abs()) {
            tfLayoutMode = 'ROW';
          }
        }
      }

      // decoBox에 visual + inputChildren 적용
      decoBox['visual'] = Map<String, dynamic>.from(visual);
      decoBox['children'] = inputChildren;
      decoBox['layoutMode'] = tfLayoutMode;
      decoBox['containerLayout'] = <String, dynamic>{
        'mainAxisAlignment': tfLayoutMode == 'ROW' ? 'start' : 'center',
        'crossAxisAlignment': tfLayoutMode == 'ROW' ? 'center' : 'start',
        'mainAxisSize': 'min',
      };
      if (paddingMap != null) {
        (decoBox['containerLayout'] as Map<String, dynamic>)['padding'] =
            paddingMap;
      }

      // floating label 있으면 → STACK으로 감싸서 border 위에 겹침
      Map<String, dynamic> mainBox;
      if (floatingLabel != null) {
        // outlined + floating label → 배경색 Frame으로 감싸서 notch 효과
        if (designInfo?.isOutlinedTextField == true &&
            designInfo?.parentBgColor != null) {
          final labelRect =
              floatingLabel['rect'] as Map<String, dynamic>? ?? {};
          floatingLabel = <String, dynamic>{
            'type': 'Frame',
            'layoutMode': 'ROW',
            'rect': labelRect,
            'containerLayout': <String, dynamic>{
              'mainAxisAlignment': 'start',
              'crossAxisAlignment': 'center',
              'mainAxisSize': 'min',
              'padding': {'top': 0.0, 'right': 4.0, 'bottom': 0.0, 'left': 4.0},
            },
            'visual': <String, dynamic>{
              'backgroundColor': designInfo!.parentBgColor,
            },
            'children': [floatingLabel],
          };
        }

        // decoBox: Stack 자식이므로 글로벌 좌표 유지
        decoBox['rect'] = {'x': decoX, 'y': decoY, 'w': decoW, 'h': decoH};
        // label: 글로벌 좌표 유지 (STACK이 부모 rect 기준으로 상대 변환)
        mainBox = <String, dynamic>{
          'type': 'Frame',
          'layoutMode': 'STACK',
          'rect': {'x': decoX, 'y': decoY, 'w': decoW, 'h': decoH},
          'visual': <String, dynamic>{},
          'containerLayout': <String, dynamic>{},
          'children': [decoBox, floatingLabel],
        };
      } else {
        mainBox = decoBox;
      }

      if (belowChildren.isNotEmpty) {
        // 에러/헬퍼 텍스트 있음 → 외부 COLUMN
        visual.clear();
        hasVisual = false;
        layoutMode = 'COLUMN';
        isLayoutNode = true;
        containerLayout['mainAxisAlignment'] = 'start';
        containerLayout['crossAxisAlignment'] = 'stretch';
        containerLayout['mainAxisSize'] = 'min';
        containerLayout['itemSpacing'] = 4.0;

        children.clear();
        children.add(mainBox);
        children.addAll(belowChildren);
      } else {
        // 에러 없음 → mainBox를 직접 사용
        visual.clear();
        hasVisual = false;
        layoutMode = 'COLUMN';
        isLayoutNode = true;
        containerLayout['mainAxisAlignment'] = 'start';
        containerLayout['crossAxisAlignment'] = 'stretch';
        containerLayout['mainAxisSize'] = 'min';

        children.clear();
        children.add(mainBox);
      }
    }
  }

  // Flex: itemSpacing 계산 (첫 번째 순회에서 수집한 _gaps 사용)
  if (isFlex && _gaps.isNotEmpty) {
    // 모두 같으면 그 값, 다르면 가장 빈번한 값
    final allSame = _gaps.every((g) => g == _gaps.first);
    if (allSame) {
      containerLayout['itemSpacing'] = _gaps.first;
    } else {
      final freq = <double, int>{};
      for (final g in _gaps) freq[g] = (freq[g] ?? 0) + 1;
      double bestGap = _gaps.first;
      int bestCount = 0;
      freq.forEach((g, count) {
        if (count > bestCount) {
          bestGap = g;
          bestCount = count;
        }
      });
      containerLayout['itemSpacing'] = bestGap;
    }
  }

  // 배경 이미지를 synthetic Image child로 추가
  if (backgroundImagePath != null) {
    final bgChild = <String, dynamic>{
      'type': 'Image',
      'layoutMode': 'NONE',
      'rect': {
        'x': offset.dx,
        'y': offset.dy,
        'w': node.size.width,
        'h': node.size.height,
      },
      'visual': <String, dynamic>{
        'imagePath': backgroundImagePath,
        'imageFit': backgroundImageFit ?? 'cover',
      },
      'children': <Map<String, dynamic>>[],
    };
    children.insert(0, bgChild);
  }

  // ---------------------------------------------------
  // Stack 단일 자식 투과 (RefreshIndicator 등: 0-sized overlay 제거 후 1개만 남음)
  // ---------------------------------------------------
  if (node is RenderStack &&
      children.length == 1 &&
      !hasVisual &&
      !_hasVisualProps(visual)) {
    final onlyChild = children.first;
    // Stack이 부여한 FIXED sizing 제거 (불필요)
    final cl = onlyChild['childLayout'] as Map<String, dynamic>? ?? {};
    cl.remove('sizingH');
    cl.remove('sizingV');
    cl.remove('positioned');
    if (cl.isEmpty) {
      onlyChild.remove('childLayout');
    } else {
      onlyChild['childLayout'] = cl;
    }
    onlyChild['rect'] = {
      'x': offset.dx,
      'y': offset.dy,
      'w': node.size.width,
      'h': node.size.height,
    };
    return onlyChild;
  }

  // ---------------------------------------------------
  // Smart Flattening (조건 강화)
  // ---------------------------------------------------
  final bool hasPadding = containerLayout.containsKey('padding');
  if (type == 'Frame' &&
      !hasVisual &&
      !_hasVisualProps(visual) &&
      !isLayoutNode &&
      !isSizedBox &&
      layoutMode == 'NONE' &&
      !hasPadding &&
      children.length == 1) {
    // widgetName 전파 (Smart Flattening에서 소실 방지)
    if (_widgetNameByRenderObject.containsKey(node) &&
        children.first is Map<String, dynamic> &&
        !children.first.containsKey('widgetName')) {
      children.first['widgetName'] = _widgetNameByRenderObject[node];
    }
    return children.first;
  }
  if (children.isEmpty &&
      !hasVisual &&
      !_hasVisualProps(visual) &&
      (node.size.width < 1 && node.size.height < 1)) {
    return null;
  }

  // ---------------------------------------------------
  // Visual Merge + Flatten: NONE 래퍼(DecoratedBox 등)의 visual을
  // 자식 Frame에 병합하여 auto-layout 체인 유지
  // ---------------------------------------------------
  if (type == 'Frame' &&
      layoutMode == 'NONE' &&
      !isLayoutNode &&
      children.length == 1 &&
      children.first['type'] == 'Frame') {
    final child = children.first;
    final childRect = child['rect'] as Map<String, dynamic>?;
    final childW = (childRect?['w'] as num?)?.toDouble() ?? 0;
    final childH = (childRect?['h'] as num?)?.toDouble() ?? 0;

    // 자식이 부모보다 유의미하게 작으면 → merge하지 않고 센터링 컨테이너로 전환
    if ((node.size.width - childW).abs() > 4 ||
        (node.size.height - childH).abs() > 4) {
      layoutMode = 'COLUMN';
      isLayoutNode = true;
      containerLayout['mainAxisAlignment'] = 'center';
      containerLayout['crossAxisAlignment'] = 'center';
      containerLayout['mainAxisSize'] = 'max';
      // fall through → 일반 노드로 반환
    } else {
      // 같은 크기 → 기존 visual merge
      final childVisual = child['visual'] as Map<String, dynamic>;

      // outer visual → child에 병합 (child 기존 값 우선)
      visual.forEach((key, value) {
        if (value != null && !childVisual.containsKey(key)) {
          childVisual[key] = value;
        }
      });

      // outer rect 유지 (바운딩 박스)
      child['rect'] = {
        'x': offset.dx,
        'y': offset.dy,
        'w': node.size.width,
        'h': node.size.height,
      };
      // widgetName 전파 (merge 시 소실 방지)
      if (_widgetNameByRenderObject.containsKey(node) &&
          !child.containsKey('widgetName')) {
        child['widgetName'] = _widgetNameByRenderObject[node];
      }
      return child;
    }
  }

  // ---------------------------------------------------
  // 최종 노드 반환 (새 스키마)
  // ---------------------------------------------------
  final result = <String, dynamic>{
    'type': type,
    'layoutMode': layoutMode,
    'rect': {
      'x': offset.dx,
      'y': offset.dy,
      'w': node.size.width,
      'h': node.size.height,
    },
    'visual': visual,
    'children': children,
  };
  if (containerLayout.isNotEmpty) result['containerLayout'] = containerLayout;
  if (_widgetNameByRenderObject.containsKey(node)) {
    result['widgetName'] = _widgetNameByRenderObject[node];
  }

  // clipsContent 전파: 부모가 clipsContent + borderRadius 이면,
  // 동일 borderRadius를 가진 직계 자식에도 clipsContent 전파
  // (Card → Material 구조: RenderPhysicalModel → RenderDecoratedBox 중복 방지)
  if (visual['clipsContent'] == true && visual['borderRadius'] != null) {
    final parentBr = visual['borderRadius'];
    for (final child in children) {
      if (child is Map<String, dynamic>) {
        final cv = child['visual'] as Map<String, dynamic>?;
        if (cv != null &&
            cv['borderRadius'] != null &&
            cv['borderRadius'].toString() == parentBr.toString() &&
            cv['clipsContent'] != true) {
          cv['clipsContent'] = true;
        }
      }
    }
  }

  // childLayout은 부모가 설정 (위에서 이미 설정됨)
  return result;
}

/// =======================================================
/// 4. 겹친 화면 제거
/// =======================================================

/// 재귀적으로 Scaffold를 찾아 마지막 것만 남긴다.
/// Navigator 스택에 여러 페이지가 쌓여 있을 때,
/// 최상위(마지막) Scaffold만 보존.
Map<String, dynamic> _keepLastScaffold(Map<String, dynamic> root) {
  final children = root['children'] as List<Map<String, dynamic>>?;
  if (children == null || children.isEmpty) return root;

  // 현재 레벨에서 Scaffold 찾기
  final scaffoldIndices = <int>[];
  for (int i = 0; i < children.length; i++) {
    if (_containsScaffold(children[i])) {
      scaffoldIndices.add(i);
    }
  }

  if (scaffoldIndices.length > 1) {
    // 마지막 Scaffold가 있는 자식만 남기고 나머지 Scaffold 자식 제거
    final lastIdx = scaffoldIndices.last;
    final filtered = <Map<String, dynamic>>[];
    for (int i = 0; i < children.length; i++) {
      if (scaffoldIndices.contains(i) && i != lastIdx) continue;
      filtered.add(children[i]);
    }
    root['children'] = filtered;
  } else {
    // 이 레벨에 Scaffold가 0~1개면 자식으로 재귀
    for (final child in children) {
      _keepLastScaffold(child);
    }
  }
  return root;
}

bool _containsScaffold(Map<String, dynamic> node) {
  if (node['widgetName'] == 'Scaffold') return true;
  final children = node['children'] as List?;
  if (children == null) return false;
  for (final child in children) {
    if (child is Map<String, dynamic> && _containsScaffold(child)) return true;
  }
  return false;
}

/// =======================================================
/// 5. 외부 진입점
/// =======================================================

String figmaExtractorEntryPoint() {
  try {
    debugPrint('[FigmaCrawler] ===== START (v2) =====');
    _designInfoByRenderObject.clear();
    _svgBoxTargets.clear();
    _widgetNameByRenderObject.clear();
    _customPaintCaptures.clear();
    _blurInfoByRenderObject.clear();
    _rotationByRenderObject.clear();
    _shaderMaskWidgets.clear();
    _customPainterByRO.clear();
    _clipperByRenderObject.clear();
    _boxFitByRenderObject.clear();
    _rotatedBoxNodes.clear();
    // _shaderMaskGradients, _clipPathPoints는 async phase에서 채워지므로 여기서 clear하지 않음

    final rootElement = WidgetsBinding.instance.renderViewElement;
    if (rootElement != null) {
      try {
        rootElement.visitChildren(_collectDesignInfoFromElements);
      } catch (e, st) {
        debugPrint('[FigmaCrawler] Step 1 ERROR: $e\n$st');
      }
    }

    final root = RendererBinding.instance.renderView;
    final List<Map<String, dynamic>> rootChildren = [];
    root.visitChildren((child) {
      final res = _crawl(child);
      if (res != null) rootChildren.add(res);
    });

    double maxWidth = 0.0;
    double maxHeight = 0.0;
    try {
      maxWidth = root.size.width;
      maxHeight = root.size.height;
    } catch (_) {}

    final ui.Size screenSize = ui.Size(
      maxWidth > 0 ? maxWidth : 390.0,
      maxHeight > 0 ? maxHeight : 844.0,
    );

    final data = <String, dynamic>{
      'type': 'Frame',
      'name': 'Flutter Screen',
      'layoutMode': 'COLUMN',
      'rect': {
        'x': 0.0,
        'y': 0.0,
        'w': screenSize.width,
        'h': screenSize.height,
      },
      'visual': {'backgroundColor': '#ffffffff'},
      'containerLayout': {
        'mainAxisAlignment': 'start',
        'crossAxisAlignment': 'stretch',
        'mainAxisSize': 'max',
        'itemSpacing': 0.0,
        'padding': {'top': 0.0, 'right': 0.0, 'bottom': 0.0, 'left': 0.0},
      },
      'children': rootChildren,
    };

    _keepLastScaffold(data);

    final result = jsonEncode(data);
    debugPrint('[FigmaCrawler] ===== DONE (${result.length} chars) =====');
    return result;
  } catch (e, st) {
    debugPrint('[FigmaCrawler] FATAL ERROR: $e\n$st');
    return jsonEncode({'error': e.toString(), 'stackTrace': st.toString()});
  }
}

/// =======================================================
/// 5.5. 스크롤 위치 수집
/// =======================================================

List<ScrollPosition> _collectScrollPositions(Element? rootElement) {
  final List<ScrollPosition> positions = [];
  if (rootElement == null) return positions;
  void visit(Element element) {
    final widget = element.widget;
    if (widget is Scrollable) {
      try {
        final scrollable =
            (element as StatefulElement).state as ScrollableState;
        positions.add(scrollable.position);
      } catch (_) {}
    }
    element.visitChildren(visit);
  }

  rootElement.visitChildren(visit);
  return positions;
}

/// =======================================================
/// 6. Async export (이미지 pre-capture 포함)
/// =======================================================

Future<String> _figmaExportWithImagesAsync() async {
  _imageDataByNode.clear();
  _customPaintCaptures.clear();
  _blurInfoByRenderObject.clear();
  _rotationByRenderObject.clear();
  _shaderMaskWidgets.clear();
  _shaderMaskGradients.clear();
  _customPainterByRO.clear();
  _clipperByRenderObject.clear();
  _clipPathPoints.clear();
  _boxFitByRenderObject.clear();
  _rotatedBoxNodes.clear();

  // Phase 0: Element tree 순회 → _customPaintCaptures 등록 (pre-capture에 필요)
  final rootElement = WidgetsBinding.instance.renderViewElement;
  if (rootElement != null) {
    try {
      rootElement.visitChildren(_collectDesignInfoFromElements);
    } catch (_) {}
  }

  final root = RendererBinding.instance.renderView;

  // Phase 0.2: ClipPath path 샘플링
  _clipPathPoints.clear();
  for (final entry in _clipperByRenderObject.entries) {
    final ro = entry.key;
    final clipper = entry.value;
    if (ro is RenderBox && ro.hasSize) {
      try {
        final path = clipper.getClip(ro.size);
        final points = <Map<String, double>>[];
        for (final metric in path.computeMetrics()) {
          const step = 2.0;
          for (double d = 0; d <= metric.length; d += step) {
            final tangent = metric.getTangentForOffset(d);
            if (tangent != null) {
              points.add({'x': tangent.position.dx, 'y': tangent.position.dy});
            }
          }
          final last = metric.getTangentForOffset(metric.length);
          if (last != null) {
            points.add({'x': last.position.dx, 'y': last.position.dy});
          }
        }
        if (points.isNotEmpty) {
          _clipPathPoints[ro] = points;
          debugPrint('[ClipPath] sampled ${points.length} points for $ro');
        }
      } catch (e) {
        debugPrint('[ClipPath] path sampling failed: $e');
      }
    }
  }

  // Phase 0.3: ShaderMask gradient 추출 (render tree에서 캡처 후 픽셀 샘플링)
  await _extractShaderMaskGradients(root);

  // Phase 0.5: 스크롤 뷰 pre-scroll → viewport 밖 위젯도 paint 강제
  final scrollPositions = _collectScrollPositions(rootElement);
  final Map<ScrollPosition, double> originalOffsets = {};
  for (final pos in scrollPositions) {
    originalOffsets[pos] = pos.pixels;
  }
  for (final pos in scrollPositions) {
    if (pos.maxScrollExtent <= 0) continue;
    final viewportDim = pos.viewportDimension;
    double current = 0;
    while (current < pos.maxScrollExtent) {
      current = (current + viewportDim).clamp(0.0, pos.maxScrollExtent);
      pos.jumpTo(current);
      await WidgetsBinding.instance.endOfFrame;
      await _preCaptureImages(root);
    }
  }
  // 원래 스크롤 위치로 복원
  for (final pos in scrollPositions) {
    pos.jumpTo(originalOffsets[pos] ?? 0.0);
  }
  await WidgetsBinding.instance.endOfFrame;

  // Phase 1: async pre-capture (상단 viewport 위젯 포함)
  await _preCaptureImages(root);

  // Phase 2: 기존 sync 크롤 (figmaExtractorEntryPoint 재사용)
  // Note: figmaExtractorEntryPoint 내부에서 _customPaintCaptures를 다시 채우지만,
  //       _imageDataByNode는 유지되므로 캡처 이미지가 정상 사용됨
  final result = figmaExtractorEntryPoint();

  _imageDataByNode.clear(); // 메모리 해제
  return result;
}

/// CLI에서 호출: evaluate('figmaStartExportWithImages()') 또는 figmaStartExportWithImages(4.0)
void figmaStartExportWithImages([double pixelRatio = 3.0]) {
  _capturePixelRatio = pixelRatio;
  _asyncExportBusy = true;
  _asyncExportResult = null;
  _figmaExportWithImagesAsync().then((r) {
    _asyncExportResult = r;
    _asyncExportBusy = false;
  }).catchError((e) {
    _asyncExportResult = '{"error":"$e"}';
    _asyncExportBusy = false;
  });
}

/// CLI에서 폴링: evaluate('figmaGetExportResult()')
String? figmaGetExportResult() {
  if (_asyncExportBusy) return null;
  return _asyncExportResult;
}
